{
  "name": "Project Vibe: Life Story & Wisdom Agent",
  "description": "A gentle, long-term system for listening to older adults, preserving their life stories, and distilling lived wisdom for future generations.",
  "requestFramePermissions": [
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum LifePhase {
  CHILDHOOD = 'Childhood',
  YOUTH = 'Youth',
  ADULTHOOD = 'Adulthood',
  SENIORITY = 'Seniority'
}

export interface TimelineEvent {
  id: string;
  event: string;
  timeRange: string;
  phase: LifePhase;
  evidenceSessions: string[];
  description: string;
}

export interface LifeWisdom {
  id: string;
  belief: string;
  explanation: string;
  tags: string[];
}

export interface MemorySession {
  id: string;
  timestamp: number;
  theme: string;
  transcript: string;
  distilledStory?: string;
}

export interface LifeMemoryStore {
  sessions: MemorySession[];
  timeline: TimelineEvent[];
  wisdoms: LifeWisdom[];
}

export type Step = 'intro' | 'theme' | 'listen' | 'reflect' | 'distill' | 'timeline' | 'legacy';

import { GoogleGenAI, Type } from "@google/genai";
import { LifePhase, TimelineEvent, LifeWisdom } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const distillStory = async (transcript: string, theme: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Please transform the following messy transcript into a cohesive, first-person narrative story centered around the theme: "${theme}". 
    The story should be gentle, respect the speaker's original tone, and remove filler words or irrelevant repetitions. 
    Transcript: ${transcript}`,
    config: {
      temperature: 0.7,
    }
  });
  return response.text;
};

export const extractWisdomAndEvents = async (transcript: string, existingTimeline: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Based on this life story session transcript: "${transcript}", identify core life wisdoms (beliefs) and significant life events.
    Existing Timeline context: ${existingTimeline}

    Output in JSON format with two keys: "wisdoms" and "events".
    For each wisdom, provide "belief" and "explanation".
    For each event, provide "event" (title), "timeRange", "phase" (one of: Childhood, Youth, Adulthood, Seniority), and "description".`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          wisdoms: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                belief: { type: Type.STRING },
                explanation: { type: Type.STRING }
              },
              required: ["belief", "explanation"]
            }
          },
          events: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                event: { type: Type.STRING },
                timeRange: { type: Type.STRING },
                phase: { type: Type.STRING },
                description: { type: Type.STRING }
              },
              required: ["event", "phase"]
            }
          }
        },
        required: ["wisdoms", "events"]
      }
    }
  });

  try {
    return JSON.parse(response.text);
  } catch (e) {
    console.error("Failed to parse JSON from AI", e);
    return { wisdoms: [], events: [] };
  }
};

export const getClarifyingQuestion = async (transcript: string, theme: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `The speaker is sharing a memory about "${theme}". 
    Current transcript: "${transcript}"
    If the story feels incomplete or lacks detail, ask ONE very gentle, open-ended clarifying question to help them go deeper. 
    If the story is already complete, respond with "PROCEED".`,
    config: {
      temperature: 0.5,
      systemInstruction: "You are a patient, empathetic listener. You do not interrupt. You value details over speed."
    }
  });
  return response.text;
};

import React from 'react';

