          <h1 className="serif text-4xl font-light text-stone-900 tracking-tight" onClick={onHomeClick} style={{ cursor: onHomeClick ? 'pointer' : 'default' }}>
            {title || "Project Vibe"}
          </h1>
          {subtitle && <p className="mt-2 text-stone-500 font-light">{subtitle}</p>}
        </div>
