import React, { useState, useEffect, useRef } from 'react';

interface ListeningModuleProps {
  theme: string;
  onFinish: (transcript: string) => void;
}

const ListeningModule: React.FC<ListeningModuleProps> = ({ theme, onFinish }) => {
  const [isListening, setIsListening] = useState(false);
  const [transcript, setTranscript] = useState('');
  const [volume, setVolume] = useState(0);
  const recognitionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);

  useEffect(() => {
    // Setup Speech Recognition
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = true;
      recognitionRef.current.interimResults = true;
      recognitionRef.current.onresult = (event: any) => {
        let interim = '';
        let final = '';
        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) {
            final += event.results[i][0].transcript;
          } else {
            interim += event.results[i][0].transcript;
          }
        }
        setTranscript(prev => prev + ' ' + final);
      };
    }

    return () => {
      if (recognitionRef.current) recognitionRef.current.stop();
    };
  }, []);

  const startListening = async () => {
    setIsListening(true);
    if (recognitionRef.current) recognitionRef.current.start();

    // Start audio visualization
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      const source = audioContextRef.current.createMediaStreamSource(stream);
      analyserRef.current = audioContextRef.current.createAnalyser();
      analyserRef.current.fftSize = 256;
      source.connect(analyserRef.current);

      const bufferLength = analyserRef.current.frequencyBinCount;
      const dataArray = new Uint8Array(bufferLength);

      const updateVolume = () => {
        if (!analyserRef.current) return;
        analyserRef.current.getByteFrequencyData(dataArray);
        const average = dataArray.reduce((a, b) => a + b) / bufferLength;
        setVolume(average);
        if (isListening) requestAnimationFrame(updateVolume);
      };
      updateVolume();
    } catch (err) {
      console.error("Microphone access denied", err);
    }
  };

  const stopListening = () => {
    setIsListening(false);
    if (recognitionRef.current) recognitionRef.current.stop();
    if (audioContextRef.current) audioContextRef.current.close();
    // In a real app, we'd wait for the final transcript segment
    setTimeout(() => onFinish(transcript), 1000);
  };

  return (
    <div className="flex flex-col items-center justify-center space-y-12 py-10">
      <div className="text-center space-y-4">
        <h2 className="serif text-3xl font-light italic">Currently listening to: {theme}</h2>
        <p className="text-stone-500 max-w-md mx-auto">
          Please speak at your own pace. There is no rush. Your silence is as important as your words.
        </p>
      </div>

      <div className="relative flex items-center justify-center h-64 w-64">
        {/* Pulsing circle based on volume */}
        <div 
          className="absolute inset-0 bg-stone-100 rounded-full transition-transform duration-100"
          style={{ transform: `scale(${1 + (volume / 255) * 1.5})`, opacity: isListening ? 0.3 : 0 }}
        />
        <button
          onClick={isListening ? stopListening : startListening}
          className={`relative z-10 w-32 h-32 rounded-full flex items-center justify-center transition-all duration-500 shadow-lg ${
            isListening ? 'bg-stone-800 scale-110' : 'bg-stone-200 hover:bg-stone-300'
          }`}
        >
          {isListening ? (
            <div className="w-8 h-8 bg-white rounded-sm animate-pulse" />
          ) : (
            <div className="w-8 h-8 border-t-2 border-r-2 border-stone-600 rotate-45 ml-[-4px]" />
          )}
        </button>
      </div>

      <div className="w-full max-w-xl min-h-32 p-6 bg-white border border-stone-100 rounded-lg shadow-sm">
        <p className="text-stone-400 italic font-light">
          {transcript || "The transcript will appear here as you speak..."}
        </p>
      </div>

      {isListening && (
        <p className="text-sm text-stone-400 animate-pulse font-medium tracking-widest uppercase">
          RECORDING LIFE STORY
        </p>
      )}
    </div>
  );
};

export default ListeningModule;

import React from 'react';
import { TimelineEvent, LifePhase } from '../types';

interface TimelineViewProps {
  events: TimelineEvent[];
}

const TimelineView: React.FC<TimelineViewProps> = ({ events }) => {
  const sortedEvents = [...events].sort((a, b) => {
    const order = [LifePhase.CHILDHOOD, LifePhase.YOUTH, LifePhase.ADULTHOOD, LifePhase.SENIORITY];
    return order.indexOf(a.phase) - order.indexOf(b.phase);
  });

  return (
    <div className="relative py-10 pl-8 space-y-12">
      {/* Central Line */}
      <div className="absolute left-[3.5px] top-0 bottom-0 w-[1px] bg-stone-200" />

      {sortedEvents.map((event, idx) => (
        <div key={event.id} className="relative group">
          {/* Dot */}
          <div className="absolute left-[-32.5px] top-1.5 w-4 h-4 rounded-full border-2 border-white bg-stone-400 shadow-sm group-hover:bg-stone-900 transition-colors" />

          <div className="space-y-2">
            <div className="flex items-center space-x-3">
              <span className="text-xs font-semibold uppercase tracking-widest text-stone-400">
                {event.phase} {event.timeRange ? `• ${event.timeRange}` : ''}
              </span>
            </div>
            <h3 className="serif text-xl font-medium text-stone-900">{event.event}</h3>
            <p className="text-stone-600 font-light leading-relaxed max-w-2xl">
              {event.description}
            </p>
          </div>
        </div>
      ))}

      {sortedEvents.length === 0 && (
        <div className="text-stone-400 italic font-light py-20 text-center w-full">
          The life path will emerge as more memories are shared.
        </div>
      )}
    </div>
  );
};

export default TimelineView;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import ListeningModule from './components/ListeningModule';
import TimelineView from './components/TimelineView';
import { 
  Step, 
  LifeMemoryStore, 
  MemorySession, 
  LifePhase, 
  TimelineEvent, 
  LifeWisdom 
} from './types';
import { 
  distillStory, 
  extractWisdomAndEvents, 
  getClarifyingQuestion 
} from './services/geminiService';

const STORAGE_KEY = 'project_vibe_store_v1';

const App: React.FC = () => {
  const [step, setStep] = useState<Step>('intro');
  const [loading, setLoading] = useState(false);
  const [currentTheme, setCurrentTheme] = useState('');
  const [currentTranscript, setCurrentTranscript] = useState('');
  const [clarifyingQuestion, setClarifyingQuestion] = useState<string | null>(null);
  const [distilledPreview, setDistilledPreview] = useState<string>('');

  // Persistence state
  const [store, setStore] = useState<LifeMemoryStore>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : { sessions: [], timeline: [], wisdoms: [] };
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(store));
  }, [store]);

  const themes = [
    "Childhood Home & Early Sights",
    "A Turning Point in Youth",
    "The Meaning of Family",
    "Lessons from a Great Challenge",
    "Reflections on Career & Passion",
    "Love, Friendship, and Loss"
  ];

  const handleFinishListening = async (transcript: string) => {
    setCurrentTranscript(transcript);
    setLoading(true);
    try {
      const question = await getClarifyingQuestion(transcript, currentTheme);
      if (question === 'PROCEED') {
        processSession(transcript);
      } else {
        setClarifyingQuestion(question);
        setStep('reflect');
      }
    } catch (e) {
      console.error(e);
      processSession(transcript);
    } finally {
      setLoading(false);
    }
  };

  const processSession = async (transcript: string) => {
    setLoading(true);
    setStep('distill');
    try {
      const distilled = await distillStory(transcript, currentTheme);
      setDistilledPreview(distilled || '');

      const existingTimelineStr = store.timeline.map(e => `${e.phase}: ${e.event}`).join(', ');
      const extracted = await extractWisdomAndEvents(transcript, existingTimelineStr);

      const newSession: MemorySession = {
        id: Date.now().toString(),
        timestamp: Date.now(),
        theme: currentTheme,
        transcript: transcript,
        distilledStory: distilled
      };

      // Merge new wisdoms and events, avoiding obvious duplicates
      setStore(prev => ({
        ...prev,
        sessions: [...prev.sessions, newSession],
        wisdoms: [...prev.wisdoms, ...extracted.wisdoms.map((w: any) => ({ ...w, id: Math.random().toString() }))],
        timeline: [...prev.timeline, ...extracted.events.map((e: any) => ({ ...e, id: Math.random().toString() }))]
      }));

    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const renderIntro = () => (
    <div className="flex flex-col items-center justify-center space-y-8 py-10 text-center animate-fade-in">
      <div className="max-w-2xl space-y-6">
        <h2 className="serif text-5xl font-light text-stone-900">Listening to life.</h2>
        <p className="text-xl text-stone-500 font-light leading-relaxed">
          This is a space to honor your journey. We don't just record sounds; we harvest wisdom, 
          bridging the gap between memories and the future.
        </p>
      </div>
      <div className="flex space-x-4 pt-10">
        <button 
          onClick={() => setStep('theme')}
          className="px-10 py-4 bg-stone-900 text-white rounded-full font-medium shadow-xl hover:bg-stone-800 transition-all hover:translate-y-[-2px]"
        >
          Share a New Memory
        </button>
        <button 
          onClick={() => setStep('timeline')}
          className="px-10 py-4 border border-stone-200 text-stone-600 rounded-full font-medium hover:bg-stone-50 transition-all"
        >
          View Life Path
        </button>
      </div>
    </div>
  );

  const renderThemeSelection = () => (
    <div className="space-y-12">
      <div className="text-center">
        <h2 className="serif text-3xl font-light">What would you like to reflect on today?</h2>
        <p className="text-stone-400 mt-2">A theme helps us focus, but your story can go anywhere.</p>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {themes.map((t) => (
          <button
            key={t}
            onClick={() => { setCurrentTheme(t); setStep('listen'); }}
            className="p-8 text-left border border-stone-100 bg-white rounded-xl shadow-sm hover:shadow-md hover:border-stone-200 transition-all group"
          >
            <h3 className="serif text-xl group-hover:text-stone-900 text-stone-700">{t}</h3>
            <p className="text-sm text-stone-400 mt-2">Begin sharing your perspective...</p>
          </button>
        ))}
      </div>
    </div>
  );

  const renderReflect = () => (
    <div className="space-y-12 max-w-2xl mx-auto py-10">
      <div className="p-8 bg-stone-50 rounded-2xl border border-stone-100 italic serif text-2xl text-stone-800 leading-relaxed">
        "{clarifyingQuestion}"
      </div>
      <div className="flex flex-col items-center space-y-4">
        <p className="text-stone-500 text-center">
          The listener heard you, but wants to know a bit more. Would you like to expand, or should we continue?
        </p>
        <div className="flex space-x-4 pt-4">
          <button 
            onClick={() => setStep('listen')}
            className="px-8 py-3 bg-stone-900 text-white rounded-full font-medium"
          >
            Expand Story
          </button>
          <button 
            onClick={() => processSession(currentTranscript)}
            className="px-8 py-3 border border-stone-200 text-stone-600 rounded-full font-medium"
          >
            Finalize Here
          </button>
        </div>
      </div>
    </div>
  );

  const renderDistill = () => (
    <div className="space-y-10 py-10 animate-fade-in">
      {loading ? (
        <div className="text-center space-y-6 py-20">
          <div className="animate-spin h-10 w-10 border-4 border-stone-200 border-t-stone-800 rounded-full mx-auto" />
          <p className="serif text-2xl italic text-stone-500">Refining the narrative and harvesting wisdom...</p>
        </div>
      ) : (
        <div className="space-y-12">
          <div className="max-w-3xl mx-auto space-y-6">
            <h2 className="serif text-4xl text-stone-900 border-b border-stone-100 pb-4">The Distilled Story</h2>
            <div className="prose prose-stone max-w-none">
              <p className="serif text-2xl font-light italic text-stone-700 leading-relaxed whitespace-pre-wrap">
                {distilledPreview}
              </p>
            </div>
          </div>
          <div className="flex justify-center pt-10">
            <button 
              onClick={() => setStep('timeline')}
              className="px-10 py-4 bg-stone-900 text-white rounded-full font-medium shadow-lg hover:shadow-xl transition-all"
            >
              See Life Evolution
            </button>
          </div>
        </div>
      )}
    </div>
  );

  const renderTimeline = () => (
    <div className="space-y-12">
      <div className="flex justify-between items-center">
        <h2 className="serif text-4xl font-light">The Cumulative Timeline</h2>
        <button 
          onClick={() => setStep('theme')}
          className="text-stone-500 hover:text-stone-900 text-sm font-medium border-b border-stone-300 pb-1"
        >
          + Add New Memory
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
        <div className="lg:col-span-2">
          <TimelineView events={store.timeline} />
        </div>
        <div className="space-y-8">
          <h3 className="text-sm font-semibold uppercase tracking-widest text-stone-400">Distilled Wisdom</h3>
          {store.wisdoms.map((w, i) => (
            <div key={i} className="wisdom-card p-6 rounded-2xl space-y-3">
              <h4 className="serif text-lg font-medium text-stone-800">“{w.belief}”</h4>
              <p className="text-sm text-stone-500 font-light leading-relaxed italic">{w.explanation}</p>
            </div>
          ))}
          {store.wisdoms.length === 0 && (
            <p className="text-stone-400 italic text-sm">Wisdom will be extracted as you share stories.</p>
          )}
        </div>
      </div>

      <div className="flex justify-center pt-12">
        <button 
          onClick={() => setStep('legacy')}
          className="px-10 py-4 bg-stone-100 text-stone-700 rounded-full font-medium hover:bg-stone-200 transition-all"
        >
          Preview Legacy View
        </button>
      </div>
    </div>
  );

  const renderLegacy = () => (
    <div className="max-w-3xl mx-auto space-y-16 py-10 pb-40">
      <div className="text-center space-y-4">
        <h2 className="serif text-5xl font-light tracking-tight">The Living Archive</h2>
        <p className="text-stone-400 italic">For the ones who come after us.</p>
      </div>

      <div className="space-y-12">
        <section className="space-y-8">
          <h3 className="text-xs font-bold uppercase tracking-[0.3em] text-stone-300 text-center border-b border-stone-100 pb-4">Core Life Beliefs</h3>
          <div className="grid gap-8">
            {store.wisdoms.map((w, i) => (
              <div key={i} className="text-center space-y-4 max-w-xl mx-auto">
                <span className="text-stone-300 serif italic text-xl">“</span>
                <p className="serif text-3xl font-light text-stone-800 leading-tight">{w.belief}</p>
                <p className="text-stone-500 font-light">{w.explanation}</p>
              </div>
            ))}
          </div>
        </section>

        <section className="space-y-8 pt-10">
          <h3 className="text-xs font-bold uppercase tracking-[0.3em] text-stone-300 text-center border-b border-stone-100 pb-4">The Tapestry of Events</h3>
          <div className="space-y-12">
            {store.timeline.map((event, i) => (
              <div key={i} className="flex flex-col md:flex-row gap-8 items-start">
                <div className="md:w-32 flex-shrink-0 text-stone-400 text-sm font-medium pt-1">
                  {event.phase}
                </div>
                <div className="space-y-2">
                  <h4 className="serif text-2xl font-medium text-stone-900">{event.event}</h4>
                  <p className="text-stone-600 font-light leading-relaxed">{event.description}</p>
                </div>
              </div>
            ))}
          </div>
        </section>
      </div>

      <div className="fixed bottom-10 left-1/2 -translate-x-1/2">
        <button 
          onClick={() => setStep('intro')}
          className="px-12 py-4 bg-stone-900 text-white rounded-full shadow-2xl font-medium hover:bg-stone-800 transition-all"
        >
          Return to Archive
        </button>
      </div>
    </div>
  );

  return (
    <Layout onHomeClick={() => setStep('intro')}>
      {step === 'intro' && renderIntro()}
      {step === 'theme' && renderThemeSelection()}
      {step === 'listen' && <ListeningModule theme={currentTheme} onFinish={handleFinishListening} />}
      {step === 'reflect' && renderReflect()}
      {step === 'distill' && renderDistill()}
      {step === 'timeline' && renderTimeline()}
      {step === 'legacy' && renderLegacy()}
    </Layout>
  );
};

export default App;

export enum LifePhase {
  CHILDHOOD = 'Childhood',
  YOUTH = 'Youth',
  ADULTHOOD = 'Adulthood',
  SENIORITY = 'Seniority'
}

export type Language = 'en-US' | 'zh-CN' | 'zh-HK' | 'auto';

export interface TimelineEvent {
  id: string;
  event: string;
  timeRange: string;
  phase: LifePhase;
  evidenceSessions: string[];
  description: string;
}

export interface LifeWisdom {
  id: string;
  belief: string;
  explanation: string;
  tags: string[];
}

export interface MemorySession {
  id: string;
  timestamp: number;
  theme: string;
  transcript: string;
  language: Language;
  distilledStory?: string;
}

export interface LifeMemoryStore {
  sessions: MemorySession[];
  timeline: TimelineEvent[];
  wisdoms: LifeWisdom[];
}

export type Step = 'intro' | 'theme' | 'listen' | 'reflect' | 'distill' | 'timeline' | 'legacy';

import { GoogleGenAI, Type } from "@google/genai";
import { LifePhase, TimelineEvent, LifeWisdom } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const distillStory = async (transcript: string, theme: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Please transform the following transcript into a cohesive, first-person narrative story centered around the theme: "${theme}". 

    CRITICAL: The transcript might contain multiple languages (e.g., English, Mandarin, Cantonese) or code-switching. 
    Your task is to:
    1. Understand the core story across all languages used.
    2. Write the final distilled story in the primary language used by the speaker, or a clear, refined version that preserves their original cultural "vibe".
    3. Respect the speaker's original tone, remove filler words, and irrelevant repetitions.

    Transcript: ${transcript}`,
    config: {
      temperature: 0.7,
      systemInstruction: "You are a master oral historian who specializes in preserving multi-generational and multi-cultural memories. You handle mixed-language narratives with grace."
    }
  });
  return response.text;
};

export const extractWisdomAndEvents = async (transcript: string, existingTimeline: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Based on this life story session transcript: "${transcript}", identify core life wisdoms (beliefs) and significant life events.
    The transcript may be in multiple languages; please synthesize the meaning accurately.
    Existing Timeline context: ${existingTimeline}

    Output in JSON format with two keys: "wisdoms" and "events".
    For each wisdom, provide "belief" and "explanation" in the speaker's likely preferred output language (defaulting to the primary language of the session).
    For each event, provide "event" (title), "timeRange", "phase" (one of: Childhood, Youth, Adulthood, Seniority), and "description".`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          wisdoms: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                belief: { type: Type.STRING },
                explanation: { type: Type.STRING }
              },
              required: ["belief", "explanation"]
            }
          },
          events: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                event: { type: Type.STRING },
                timeRange: { type: Type.STRING },
                phase: { type: Type.STRING },
                description: { type: Type.STRING }
              },
              required: ["event", "phase"]
            }
          }
        },
        required: ["wisdoms", "events"]
      }
    }
  });

  try {
    return JSON.parse(response.text);
  } catch (e) {
    console.error("Failed to parse JSON from AI", e);
    return { wisdoms: [], events: [] };
  }
};

export const getClarifyingQuestion = async (transcript: string, theme: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `The speaker is sharing a memory about "${theme}". 
    Current transcript (may be mixed language): "${transcript}"
    If the story feels incomplete or lacks detail, ask ONE very gentle, open-ended clarifying question in the SAME LANGUAGE(S) used by the speaker to help them go deeper. 
    If the story is already complete, respond with "PROCEED".`,
    config: {
      temperature: 0.5,
      systemInstruction: "You are a patient, empathetic multi-lingual listener. You value depth and nuances. You respond in the speaker's language."
    }
  });
  return response.text;
};

import React, { useState, useEffect, useRef } from 'react';
import { Language } from '../types';

interface ListeningModuleProps {
  theme: string;
  onFinish: (transcript: string, language: Language) => void;
}

const ListeningModule: React.FC<ListeningModuleProps> = ({ theme, onFinish }) => {
  const [isListening, setIsListening] = useState(false);
  const [transcript, setTranscript] = useState('');
  const [volume, setVolume] = useState(0);
  const [selectedLang, setSelectedLang] = useState<Language>('en-US');
  const recognitionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);

  const languages: { label: string; value: Language }[] = [
    { label: 'English', value: 'en-US' },
    { label: '简体中文', value: 'zh-CN' },
    { label: '廣東話', value: 'zh-HK' },
  ];

  useEffect(() => {
    // Re-initialize recognition when language changes
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      if (recognitionRef.current) {
        recognitionRef.current.stop();
      }
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = true;
      recognitionRef.current.interimResults = true;
      recognitionRef.current.lang = selectedLang === 'auto' ? 'en-US' : selectedLang;

      recognitionRef.current.onresult = (event: any) => {
        let final = '';
        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) {
            final += event.results[i][0].transcript;
          }
        }
        if (final) {
          setTranscript(prev => prev + ' ' + final);
        }
      };

      recognitionRef.current.onerror = (event: any) => {
        console.error("Speech Recognition Error", event.error);
        setIsListening(false);
      };
    }

    return () => {
      if (recognitionRef.current) recognitionRef.current.stop();
    };
  }, [selectedLang]);

  const startListening = async () => {
    setIsListening(true);
    if (recognitionRef.current) {
      try {
        recognitionRef.current.start();
      } catch (e) {
        console.warn("Recognition already started or failed to start", e);
      }
    }

    // Start audio visualization
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      const source = audioContextRef.current.createMediaStreamSource(stream);
      analyserRef.current = audioContextRef.current.createAnalyser();
      analyserRef.current.fftSize = 256;
      source.connect(analyserRef.current);

      const bufferLength = analyserRef.current.frequencyBinCount;
      const dataArray = new Uint8Array(bufferLength);

      const updateVolume = () => {
        if (!analyserRef.current) return;
        analyserRef.current.getByteFrequencyData(dataArray);
        const average = dataArray.reduce((a, b) => a + b) / bufferLength;
        setVolume(average);
        if (isListening) requestAnimationFrame(updateVolume);
      };
      updateVolume();
    } catch (err) {
      console.error("Microphone access denied", err);
    }
  };

  const stopListening = () => {
    setIsListening(false);
    if (recognitionRef.current) recognitionRef.current.stop();
    if (audioContextRef.current) audioContextRef.current.close();
    // Short delay to ensure final transcript segments are processed
    setTimeout(() => onFinish(transcript, selectedLang), 1000);
  };

  return (
    <div className="flex flex-col items-center justify-center space-y-10 py-6">
      <div className="text-center space-y-4">
        <h2 className="serif text-3xl font-light italic">Currently listening to: {theme}</h2>
        <div className="flex justify-center gap-2 mt-4">
          {languages.map((lang) => (
            <button
              key={lang.value}
              disabled={isListening}
              onClick={() => setSelectedLang(lang.value)}
              className={`px-4 py-1.5 rounded-full text-xs font-medium tracking-wider uppercase transition-all ${
                selectedLang === lang.value 
                ? 'bg-stone-800 text-stone-50' 
                : 'bg-stone-100 text-stone-400 hover:bg-stone-200'
              } ${isListening ? 'opacity-50 cursor-not-allowed' : ''}`}
            >
              {lang.label}
            </button>
          ))}
        </div>
      </div>

      <div className="relative flex items-center justify-center h-64 w-64">
        <div 
          className="absolute inset-0 bg-stone-200 rounded-full transition-all duration-300 ease-out"
          style={{ 
            transform: `scale(${isListening ? 1 + (volume / 255) * 1.2 : 0.8})`, 
            opacity: isListening ? 0.2 : 0.1 
          }}
        />
        <button
          onClick={isListening ? stopListening : startListening}
          className={`relative z-10 w-32 h-32 rounded-full flex items-center justify-center transition-all duration-500 shadow-xl ${
            isListening ? 'bg-stone-900 scale-105 ring-4 ring-stone-100' : 'bg-stone-200 hover:bg-stone-300'
          }`}
        >
          {isListening ? (
            <div className="w-8 h-8 bg-white rounded-sm animate-pulse" />
          ) : (
            <div className="w-0 h-0 border-t-[10px] border-t-transparent border-l-[18px] border-l-stone-600 border-b-[10px] border-b-transparent ml-1" />
          )}
        </button>
      </div>

      <div className="w-full max-w-xl min-h-[160px] p-6 bg-white border border-stone-100 rounded-2xl shadow-sm transition-all duration-700">
        <p className="text-stone-500 font-light leading-relaxed">
          {transcript || (isListening ? "Listening..." : "Your spoken words will appear here. We respect silence and mixed languages.")}
        </p>
      </div>

      {isListening && (
        <div className="flex items-center space-x-3 text-stone-400 animate-pulse">
          <span className="h-1 w-1 bg-stone-400 rounded-full"></span>
          <p className="text-xs font-bold tracking-[0.2em] uppercase">Recording Journey</p>
          <span className="h-1 w-1 bg-stone-400 rounded-full"></span>
        </div>
      )}
    </div>
  );
};

export default ListeningModule;

