import { GoogleGenAI, Type } from "@google/genai";
import { LifePhase, TimelineEvent, LifeWisdom } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Distills raw transcript into a coherent first-person narrative.
 * Removes clutter while preserving the soul of the speech.
 */
export const distillStory = async (transcript: string, theme: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `You are an expert oral historian. Transform this messy transcript into a cohesive, first-person narrative story.
    Theme: "${theme}"
    Transcript: ${transcript}

    Guidelines:
    1. Maintain the speaker's original voice and culture.
    2. Remove "uhs", "ums", and excessive repetitions.
    3. Structure it into clear, emotional memory units.
    4. If multiple languages are used, synthesize them into a single, flowing narrative in the speaker's dominant language.`,
    config: {
      temperature: 0.4,
    }
  });
  return response.text;
};

/**
 * Higher-level reasoning to decide if a story is "complete" or needs more depth.
 */
export const analyzeNarrativeDepth = async (transcript: string, theme: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Analyze this life story session regarding the theme "${theme}".
    Current Transcript: "${transcript}"

    Decide between three actions:
    1. "ask_clarify": The story is interesting but missing specific details (who, where, feelings). Provide a gentle question.
    2. "accept": The story is rich and complete enough to extract wisdom.
    3. "abstain": The transcript is too short or doesn't relate to the theme.

    Return JSON with "decision" and "message" (the question to ask if decision is ask_clarify).`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          decision: { type: Type.STRING, enum: ["ask_clarify", "accept", "abstain"] },
          message: { type: Type.STRING }
        },
        required: ["decision"]
      }
    }
  });
  return JSON.parse(response.text);
};

/**
 * Extracts structured events and abstract wisdom with confidence scores.
 */
export const extractLifeStructure = async (transcript: string, context: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Analyze this transcript to extract life events and life wisdom.
    Context (Known Timeline): ${context}
    Transcript: ${transcript}

    Wisdom should be abstract beliefs verified by experience.
    Events should be specific markers in time.

    Return JSON with "wisdoms" and "events", each including a "confidence" (0.0 to 1.0).`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          wisdoms: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                belief: { type: Type.STRING },
                explanation: { type: Type.STRING },
                confidence: { type: Type.NUMBER }
              },
              required: ["belief", "explanation", "confidence"]
            }
          },
          events: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                event: { type: Type.STRING },
                timeRange: { type: Type.STRING },
                phase: { type: Type.STRING, enum: ["Childhood", "Youth", "Adulthood", "Seniority"] },
                description: { type: Type.STRING },
                confidence: { type: Type.NUMBER }
              },
              required: ["event", "phase", "confidence"]
            }
          }
        }
      }
    }
  });
  return JSON.parse(response.text);
};

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import ListeningModule from './components/ListeningModule';
import TimelineView from './components/TimelineView';
import { 
  Step, 
  LifeMemoryStore, 
  MemorySession, 
  LifePhase, 
  TimelineEvent, 
  LifeWisdom,
  Language
} from './types';
import { 
  distillStory, 
  extractLifeStructure, 
  analyzeNarrativeDepth 
} from './services/geminiService';

const STORAGE_KEY = 'project_vibe_store_v2';

const App: React.FC = () => {
  const [step, setStep] = useState<Step>('intro');
  const [loading, setLoading] = useState(false);
  const [currentSessionId, setCurrentSessionId] = useState<string>('');
  const [currentTheme, setCurrentTheme] = useState('');
  const [currentTranscript, setCurrentTranscript] = useState('');
  const [currentLanguage, setCurrentLanguage] = useState<Language>('en-US');
  const [aiDecision, setAiDecision] = useState<{decision: string, message?: string} | null>(null);
  const [distilledPreview, setDistilledPreview] = useState<string>('');

  const [store, setStore] = useState<LifeMemoryStore>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : { sessions: [], timeline: [], wisdoms: [] };
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(store));
  }, [store]);

  const themes = [
    "A memory from childhood",
    "A memory about family and home",
    "A memory about an important choice",
    "A memory about a difficult time",
    "A memory about a life lesson",
    "A memory about a turning point",
    "A memory about something I miss",
    "A memory about a challenge I overcame"
