import React, { useState, useEffect, useRef } from 'react';
import { Language } from '../types';

interface ListeningModuleProps {
  theme: string;
  onFinish: (transcript: string, language: Language) => void;
}

const ListeningModule: React.FC<ListeningModuleProps> = ({ theme, onFinish }) => {
  const [isListening, setIsListening] = useState(false);
  const [transcript, setTranscript] = useState('');
  const [volume, setVolume] = useState(0);
  const [selectedLang, setSelectedLang] = useState<Language>('en-US');
  const recognitionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);

  const languages: { label: string; value: Language }[] = [
    { label: 'English', value: 'en-US' },
    { label: '简体中文', value: 'zh-CN' },
    { label: '廣東話', value: 'zh-HK' },
  ];

  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      if (recognitionRef.current) recognitionRef.current.stop();
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = true;
      recognitionRef.current.interimResults = true;
      recognitionRef.current.lang = selectedLang;

      recognitionRef.current.onresult = (event: any) => {
        let final = '';
        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) final += event.results[i][0].transcript;
        }
        if (final) setTranscript(prev => prev + ' ' + final);
      };
      recognitionRef.current.onerror = () => setIsListening(false);
    }
    return () => { if (recognitionRef.current) recognitionRef.current.stop(); };
  }, [selectedLang]);

  const startListening = async () => {
    setIsListening(true);
    if (recognitionRef.current) recognitionRef.current.start();
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      const source = audioContextRef.current.createMediaStreamSource(stream);
      analyserRef.current = audioContextRef.current.createAnalyser();
      source.connect(analyserRef.current);
      const dataArray = new Uint8Array(analyserRef.current.frequencyBinCount);
      const updateVolume = () => {
        if (!analyserRef.current) return;
        analyserRef.current.getByteFrequencyData(dataArray);
        setVolume(dataArray.reduce((a, b) => a + b) / dataArray.length);
        if (isListening) requestAnimationFrame(updateVolume);
      };
      updateVolume();
    } catch (err) { console.error(err); }
  };

  const stopListening = () => {
    setIsListening(false);
    if (recognitionRef.current) recognitionRef.current.stop();
    if (audioContextRef.current) audioContextRef.current.close();
    setTimeout(() => onFinish(transcript, selectedLang), 1200);
  };

  return (
    <div className="flex flex-col items-center justify-center space-y-12 py-10 animate-fade-in">
      <div className="text-center space-y-6">
        <h2 className="serif text-4xl font-light italic text-stone-800">Listening to: {theme}</h2>
        <div className="flex justify-center space-x-2">
          {languages.map((lang) => (
            <button
              key={lang.value}
              disabled={isListening}
              onClick={() => setSelectedLang(lang.value)}
              className={`px-5 py-2 rounded-full text-[10px] font-bold tracking-[0.2em] uppercase transition-all ${
                selectedLang === lang.value 
                ? 'bg-stone-900 text-stone-50' 
                : 'bg-white border border-stone-100 text-stone-300 hover:text-stone-500'
              } ${isListening ? 'opacity-30 cursor-not-allowed' : ''}`}
            >
              {lang.label}
            </button>
          ))}
        </div>
      </div>

      <div className="relative flex items-center justify-center h-80 w-80">
        <div 
          className="absolute inset-0 bg-stone-200 rounded-full transition-all duration-300 ease-out"
          style={{ 
            transform: `scale(${isListening ? 1 + (volume / 100) * 1.5 : 0.8})`, 
            opacity: isListening ? 0.15 : 0.05 
          }}
        />
        <div 
          className="absolute inset-4 border border-stone-100 rounded-full animate-[spin_20s_linear_infinite]"
          style={{ display: isListening ? 'block' : 'none' }}
        />
        <button
          onClick={isListening ? stopListening : startListening}
          className={`relative z-10 w-40 h-40 rounded-full flex flex-col items-center justify-center transition-all duration-700 shadow-[0_20px_50px_rgba(0,0,0,0.1)] ${
            isListening ? 'bg-stone-900 ring-[20px] ring-stone-50' : 'bg-white hover:bg-stone-50 ring-[20px] ring-transparent'
          }`}
        >
          {isListening ? (
            <div className="space-y-1">
               <div className="w-10 h-10 bg-white rounded-sm" />
            </div>
          ) : (
            <div className="w-0 h-0 border-t-[15px] border-t-transparent border-l-[25px] border-l-stone-400 border-b-[15px] border-b-transparent ml-2" />
          )}
        </button>
      </div>

      <div className="w-full max-w-2xl bg-white p-10 rounded-[2.5rem] shadow-sm border border-stone-50 min-h-[200px] transition-all duration-1000">
        <p className="text-stone-400 serif text-2xl font-light italic leading-relaxed text-center">
          {transcript || (isListening ? "Gathering words..." : "Click to begin your narrative. There is no rush.")}
        </p>
      </div>

      {isListening && (
        <div className="flex items-center space-x-4">
          <div className="h-1 w-1 bg-stone-900 rounded-full animate-ping" />
          <p className="text-[10px] font-bold tracking-[0.4em] uppercase text-stone-900">Archiving Experience</p>
          <div className="h-1 w-1 bg-stone-900 rounded-full animate-ping" />
        </div>
      )}
    </div>
  );
};

export default ListeningModule;

