    }
  };

  const initializeNewSession = () => {
    const id = `sess_${Date.now()}`;
    setCurrentSessionId(id);
    setStep('theme');
  };

  const handleIdentitySubmit = () => {
    if (!nameInput.trim()) return;
    const personId = `person_${Date.now()}`;
    setStore(prev => ({
      ...prev,
      personId: personId,
      displayName: nameInput.trim()
    }));
    initializeNewSession();
  };

  const handleFinishListening = async (transcript: string, language: Language) => {
    setCurrentTranscript(transcript);
    setCurrentLanguage(language);

    if (!transcript.trim()) return;

    setLoading(true);
    try {
      const result = await analyzeNarrativeDepth(transcript, currentTheme);
      setAiDecision(result);
      if (result.decision === 'accept') {
        finalizeSession(transcript, language);
      } else {
        setStep('reflect');
      }
    } catch (e) {
      finalizeSession(transcript, language);
    } finally {
      setLoading(false);
    }
  };

  const finalizeSession = async (transcript: string, language: Language) => {
    setLoading(true);
    setStep('distill');
    try {
      const distilled = await distillStory(transcript, currentTheme);
      setDistilledPreview(distilled || '');

      const contextStr = store.timeline.map(e => `${e.phase}: ${e.event}`).join(', ');
      const { wisdoms, events } = await extractLifeStructure(transcript, contextStr);

      const newSession: MemorySession = {
        id: currentSessionId,
        timestamp: Date.now(),
        theme: currentTheme,
        transcript: transcript,
        language: language,
        distilledStory: distilled,
        status: 'completed'
      };

      setStore(prev => ({
        ...prev,
        sessions: [...prev.sessions, newSession],
        wisdoms: [...prev.wisdoms, ...wisdoms.map((w: any) => ({ 
          ...w, 
          id: `w_${Math.random()}`, 
          evidenceSessions: [currentSessionId] 
        }))],
        timeline: [...prev.timeline, ...events.map((e: any) => ({ 
          ...e, 
          id: `e_${Math.random()}`, 
          evidenceSessions: [currentSessionId] 
        }))]
      }));
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const renderIntro = () => (
    <div className="flex flex-col items-center justify-center space-y-12 py-10 text-center animate-fade-in">
      <div className="max-w-2xl space-y-6">
        <h2 className="serif text-6xl font-extralight text-stone-900 tracking-tight leading-tight">Harvesting <br/>Life Wisdom.</h2>
        <p className="text-xl text-stone-400 font-light leading-relaxed max-w-lg mx-auto">
          A patient space for older adults to weave their memories into a tapestry for the future.
        </p>
      </div>
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 w-full max-w-xl pt-10">
        <button 
          onClick={handleStartInteraction}
          className="p-8 bg-stone-900 text-stone-50 rounded-2xl text-center shadow-2xl hover:bg-stone-800 transition-all hover:-translate-y-1"
        >
          <span className="block text-xs uppercase tracking-widest opacity-50 mb-2">Preservation</span>
          <span className="text-lg font-medium">Record a New Memory</span>
        </button>
        <button 
          onClick={() => setStep('timeline')}
          className="p-8 border border-stone-200 bg-white text-stone-700 rounded-2xl text-center shadow-sm hover:shadow-md transition-all hover:-translate-y-1"
        >
          <span className="block text-xs uppercase tracking-widest opacity-50 mb-2">Legacy</span>
          <span className="text-lg font-medium">View Memory Archive</span>
        </button>
      </div>
    </div>
  );

  const renderIdentityInit = () => (
    <div className="max-w-md mx-auto space-y-12 py-20 text-center animate-fade-in">
      <div className="space-y-4">
        <h2 className="serif text-4xl font-light text-stone-900">I remember people, not sessions.</h2>
        <p className="text-stone-400 font-light text-lg">What name would you like me to remember you by?</p>
      </div>
      <div className="space-y-8">
        <div className="relative group">
          <input 
            type="text" 
            value={nameInput}
            onChange={(e) => setNameInput(e.target.value)}
            placeholder="Your name or nickname..."
            className="w-full bg-transparent border-b-2 border-stone-100 py-4 text-3xl serif text-center outline-none focus:border-stone-400 transition-all placeholder:text-stone-100"
            onKeyDown={(e) => e.key === 'Enter' && handleIdentitySubmit()}
            autoFocus
          />
        </div>
        <button 
          onClick={handleIdentitySubmit}
          disabled={!nameInput.trim()}
          className="px-12 py-4 bg-stone-900 text-white rounded-full font-medium shadow-lg disabled:bg-stone-100 disabled:text-stone-300 transition-all"
        >
          Begin My Story
        </button>
      </div>
      <p className="text-xs text-stone-300 uppercase tracking-widest">A stable identity anchors your legacy</p>
    </div>
  );

  const renderThemeSelection = () => (
    <div className="space-y-12 animate-fade-in">
      <div className="text-center space-y-4">
        <h2 className="serif text-4xl font-light text-stone-900">What do you remember today?</h2>
        <p className="text-stone-400 text-sm tracking-widest uppercase">Select a prompt to focus your narrative</p>
      </div>
      <div className="flex flex-wrap justify-center gap-4 max-w-3xl mx-auto">
        {themes.map((t) => (
          <button
            key={t}
            onClick={() => { setCurrentTheme(t); setStep('listen'); }}
            className={`px-8 py-3 rounded-full border text-sm transition-all duration-300 ${
              currentTheme === t 
              ? 'bg-stone-900 border-stone-900 text-white shadow-md' 
              : 'border-stone-200 text-stone-500 hover:border-stone-400 hover:text-stone-700'
            }`}
          >
            {t}
          </button>
        ))}
      </div>
      <div className="pt-10 flex flex-col items-center space-y-4">
        <p className="text-stone-300 italic text-sm">Theme is just a guide. Feel free to wander in your story.</p>
        <p className="text-[10px] text-stone-200 uppercase tracking-widest">Stories shared today will be part of your life archive.</p>
      </div>
    </div>
  );

  const renderReflect = () => (
    <div className="max-w-2xl mx-auto py-20 space-y-12 text-center animate-fade-in">
      <div className="space-y-8">
        <h2 className="serif text-4xl font-light text-stone-900">A Gentle Reflection</h2>
        <div className="p-10 bg-white border border-stone-100 rounded-3xl shadow-sm italic serif text-3xl text-stone-800 leading-snug">
          "{aiDecision?.message}"
        </div>
      </div>
      <div className="flex flex-col sm:flex-row justify-center items-center gap-6">
        <button 
          onClick={() => setStep('listen')}
          className="px-12 py-4 bg-stone-900 text-white rounded-full font-medium shadow-xl hover:-translate-y-1 transition-all"
        >
          Expand My Story
        </button>
        <button 
          onClick={() => finalizeSession(currentTranscript, currentLanguage)}
          className="px-12 py-4 border border-stone-200 text-stone-600 rounded-full font-medium hover:bg-stone-50"
        >
          No, That is All for Now
        </button>
      </div>
      <p className="text-stone-400 text-sm">Every detail adds depth to the legacy we're building.</p>
    </div>
  );

  const renderDistill = () => (
    <div className="max-w-3xl mx-auto py-10 animate-fade-in space-y-16">
      {loading ? (
        <div className="text-center space-y-8 py-20">
          <div className="w-12 h-12 border-2 border-stone-200 border-t-stone-800 rounded-full animate-spin mx-auto" />
          <div className="space-y-2">
            <h3 className="serif text-2xl font-light italic text-stone-500">Distilling the narrative...</h3>
            <p className="text-stone-300 text-sm uppercase tracking-widest">Preserving the soul of your words</p>
          </div>
        </div>
      ) : (
        <>
          <div className="space-y-8">
            <div className="flex items-center space-x-4 opacity-30">
              <div className="h-px bg-stone-900 flex-grow" />
              <span className="text-xs uppercase font-bold tracking-[0.4em]">Memory Harvested</span>
              <div className="h-px bg-stone-900 flex-grow" />
            </div>
            <div className="prose prose-stone max-w-none">
              <p className="serif text-4xl font-extralight text-stone-800 leading-[1.3] whitespace-pre-wrap">
                {distilledPreview}
              </p>
            </div>
          </div>
          <div className="flex justify-center">
            <button 
              onClick={() => setStep('timeline')}
              className="px-12 py-5 bg-stone-900 text-white rounded-full font-medium shadow-2xl hover:bg-stone-800 transition-all hover:scale-105"
            >
              Update My Life Archive
            </button>
          </div>
        </>
      )}
    </div>
  );

  const handleClearIdentity = () => {
    if (confirm("This will clear your identity and start a fresh archive. Are you sure?")) {
      setStore({ 
        personId: null, 
        displayName: null, 
        sessions: [], 
        timeline: [], 
        wisdoms: [] 
      });
      setStep('intro');
    }
  };

  return (
    <Layout 
      onHomeClick={() => setStep('intro')}
      subtitle={store.displayName ? `Archiving for: ${store.displayName}` : undefined}
    >
      {step === 'intro' && renderIntro()}
      {step === 'identity_init' && renderIdentityInit()}
      {step === 'theme' && renderThemeSelection()}
      {step === 'listen' && <ListeningModule theme={currentTheme} onFinish={handleFinishListening} />}
      {step === 'reflect' && renderReflect()}
      {step === 'distill' && renderDistill()}
      {step === 'timeline' && (
        <div className="animate-fade-in space-y-12">
           <div className="flex justify-between items-end border-b border-stone-100 pb-8">
            <h2 className="serif text-5xl font-light">{store.displayName ? `${store.displayName}'s Life Path` : 'The Cumulative Timeline'}</h2>
            <div className="flex space-x-6">
              <button onClick={handleStartInteraction} className="text-sm font-bold uppercase tracking-widest text-stone-400 hover:text-stone-900 transition-colors">
                + Harvest Memory
              </button>
              <button onClick={handleClearIdentity} className="text-sm font-bold uppercase tracking-widest text-stone-100 hover:text-red-300 transition-colors">
                New Identity
              </button>
            </div>
           </div>
           <div className="grid grid-cols-1 lg:grid-cols-3 gap-16">
              <div className="lg:col-span-2">
                <TimelineView events={store.timeline} />
              </div>
              <div className="space-y-12">
                <section className="space-y-6">
                  <h3 className="text-xs font-bold uppercase tracking-widest text-stone-300 border-b border-stone-50 pb-2">Distilled Wisdom</h3>
                  {store.wisdoms.map((w, i) => (
                    <div key={i} className="wisdom-card p-8 rounded-[2rem] space-y-4">
                       <h4 className="serif text-2xl leading-tight text-stone-800">“{w.belief}”</h4>
                       <p className="text-sm text-stone-500 font-light leading-relaxed">{w.explanation}</p>
                    </div>
                  ))}
                  {store.wisdoms.length === 0 && <p className="text-stone-300 italic text-sm">Wisdom emerges over time...</p>}
                </section>
              </div>
           </div>
           <div className="flex justify-center pt-20">
              <button onClick={() => setStep('legacy')} className="px-12 py-4 bg-stone-50 text-stone-400 rounded-full font-medium hover:bg-stone-100 transition-all">
                View My Future Legacy
              </button>
           </div>
        </div>
      )}
      {step === 'legacy' && (
        <div className="max-w-3xl mx-auto py-10 pb-40 space-y-24 animate-fade-in">
           <div className="text-center space-y-4">
             <h2 className="serif text-6xl font-extralight tracking-tight">The Legacy of {store.displayName}</h2>
             <p className="text-stone-300 italic uppercase text-xs tracking-[0.5em]">A living archive for future generations</p>
           </div>
           <div className="space-y-32">
              <section className="space-y-20">
                {store.wisdoms.map((w, i) => (
                  <div key={i} className="text-center space-y-8 max-w-xl mx-auto">
                    <div className="w-12 h-px bg-stone-100 mx-auto" />
                    <p className="serif text-4xl font-light text-stone-800 leading-tight tracking-tight px-4 italic">
                      “{w.belief}”
                    </p>
                    <p className="text-stone-400 font-light leading-relaxed max-w-sm mx-auto">{w.explanation}</p>
                  </div>
                ))}
              </section>
              <section className="space-y-16">
                 {store.timeline.map((event, i) => (
                   <div key={i} className="flex flex-col md:flex-row gap-12 items-start group">
                      <div className="md:w-32 flex-shrink-0 text-stone-200 text-xs font-bold uppercase tracking-[0.3em] pt-2 group-hover:text-stone-400 transition-colors">
                        {event.phase}
                      </div>
                      <div className="space-y-4">
                        <h4 className="serif text-3xl font-light text-stone-900">{event.event}</h4>
                        <p className="text-stone-500 font-light leading-relaxed text-xl">{event.description}</p>
                      </div>
                   </div>
                 ))}
              </section>
           </div>
           <div className="fixed bottom-12 left-1/2 -translate-x-1/2">
              <button onClick={() => setStep('intro')} className="px-14 py-4 bg-stone-900 text-white rounded-full shadow-[0_35px_60px_-15px_rgba(0,0,0,0.3)] hover:scale-105 active:scale-95 transition-all">
                Return to Archive
              </button>
           </div>
        </div>
      )}
    </Layout>
  );
};

export default App;

export enum LifePhase {
  CHILDHOOD = 'Childhood',
  YOUTH = 'Youth',
  ADULTHOOD = 'Adulthood',
  SENIORITY = 'Seniority'
}

export enum Visibility {
  PRIVATE = 'Private',
  FAMILY = 'Family Shared',
  LEGACY = 'Legacy'
}

export type Language = 'en-US' | 'zh-CN' | 'zh-HK' | 'auto';

export interface TimelineEvent {
  id: string;
  event: string;
  timeRange: string;
  phase: LifePhase;
  evidenceSessions: string[];
  description: string;
  confidence: number;
  visibility: Visibility;
}

export interface LifeWisdom {
  id: string;
  belief: string;
  explanation: string;
  evidenceSessions: string[];
  confidence: number;
  visibility: Visibility;
}

export interface MemorySession {
  id: string;
  timestamp: number;
  theme: string;
  transcript: string;
  language: Language;
  distilledStory?: string;
  status: 'active' | 'completed';
}

export interface PersonProfile {
  id: string;
  displayName: string;
  password?: string;
  sessions: MemorySession[];
  timeline: TimelineEvent[];
  wisdoms: LifeWisdom[];
}

export interface LifeMemoryStore {
  activePersonId: string | null;
  people: { [id: string]: PersonProfile };
}

export type Step = 'intro' | 'identity_select' | 'identity_init' | 'identity_password' | 'theme' | 'listen' | 'reflect' | 'distill' | 'timeline' | 'legacy';

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import ListeningModule from './components/ListeningModule';
import TimelineView from './components/TimelineView';
import { 
  Step, 
  LifeMemoryStore, 
  MemorySession, 
  LifePhase, 
  TimelineEvent, 
  LifeWisdom,
  Language,
  PersonProfile,
  Visibility
} from './types';
import { 
  distillStory, 
  extractLifeStructure, 
  analyzeNarrativeDepth 
} from './services/geminiService';

const STORAGE_KEY = 'project_vibe_multi_identity_v1';

const App: React.FC = () => {
  const [step, setStep] = useState<Step>('intro');
  const [loading, setLoading] = useState(false);
  const [currentSessionId, setCurrentSessionId] = useState<string>('');
  const [currentTheme, setCurrentTheme] = useState('');
  const [currentTranscript, setCurrentTranscript] = useState('');
  const [currentLanguage, setCurrentLanguage] = useState<Language>('en-US');
  const [aiDecision, setAiDecision] = useState<{decision: string, message?: string} | null>(null);
  const [distilledPreview, setDistilledPreview] = useState<string>('');
  const [nameInput, setNameInput] = useState('');
  const [passwordInput, setPasswordInput] = useState('');
  const [targetPersonId, setTargetPersonId] = useState<string | null>(null);

  const [store, setStore] = useState<LifeMemoryStore>(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    return saved ? JSON.parse(saved) : { 
      activePersonId: null, 
      people: {} 
    };
  });

  const activePerson: PersonProfile | null = store.activePersonId ? store.people[store.activePersonId] : null;

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(store));
  }, [store]);

  const themes = [
    "A memory from childhood",
    "A memory about family and home",
    "A memory about an important choice",
    "A memory about a difficult time",
    "A memory about a life lesson",
    "A memory about a turning point",
    "A memory about something I miss",
    "A memory about a challenge I overcame"
  ];

  const initializeNewSession = () => {
    const id = `sess_${Date.now()}`;
    setCurrentSessionId(id);
    setStep('theme');
  };

  const handleIdentitySelect = (personId: string) => {
    const person = store.people[personId];
    if (person.password) {
      setTargetPersonId(personId);
      setStep('identity_password');
    } else {
      setStore(prev => ({ ...prev, activePersonId: personId }));
      setStep('intro');
    }
  };

  const handlePasswordSubmit = () => {
    if (!targetPersonId) return;
    const person = store.people[targetPersonId];
    if (person.password === passwordInput) {
      setStore(prev => ({ ...prev, activePersonId: targetPersonId }));
      setStep('intro');
      setPasswordInput('');
      setTargetPersonId(null);
    } else {
      alert("Incorrect password.");
    }
  };

  const handleIdentityCreate = () => {
    if (!nameInput.trim()) return;
    const personId = `person_${Date.now()}`;
    const newPerson: PersonProfile = {
      id: personId,
      displayName: nameInput.trim(),
      password: passwordInput.trim() || undefined,
      sessions: [],
      timeline: [],
      wisdoms: []
    };
    setStore(prev => ({
      ...prev,
      activePersonId: personId,
      people: { ...prev.people, [personId]: newPerson }
    }));
    initializeNewSession();
    setNameInput('');
    setPasswordInput('');
  };

  const handleFinishListening = async (transcript: string, language: Language) => {
    setCurrentTranscript(transcript);
    setCurrentLanguage(language);
    if (!transcript.trim()) return;
    setLoading(true);
    try {
      const result = await analyzeNarrativeDepth(transcript, currentTheme);
      setAiDecision(result);
      if (result.decision === 'accept') {
        finalizeSession(transcript, language);
      } else {
        setStep('reflect');
      }
    } catch (e) {
      finalizeSession(transcript, language);
    } finally { setLoading(false); }
  };

  const finalizeSession = async (transcript: string, language: Language) => {
    if (!store.activePersonId) return;
    setLoading(true);
    setStep('distill');
    try {
      const distilled = await distillStory(transcript, currentTheme);
      setDistilledPreview(distilled || '');
      const contextStr = activePerson?.timeline.map(e => `${e.phase}: ${e.event}`).join(', ') || '';
      const { wisdoms, events } = await extractLifeStructure(transcript, contextStr);

      const newSession: MemorySession = {
        id: currentSessionId,
        timestamp: Date.now(),
        theme: currentTheme,
        transcript: transcript,
        language: language,
        distilledStory: distilled,
        status: 'completed'
      };

      setStore(prev => {
        const pId = prev.activePersonId!;
        const person = prev.people[pId];
        return {
          ...prev,
          people: {
            ...prev.people,
            [pId]: {
              ...person,
              sessions: [...person.sessions, newSession],
              wisdoms: [...person.wisdoms, ...wisdoms.map((w: any) => ({ 
                ...w, id: `w_${Math.random()}`, evidenceSessions: [currentSessionId], visibility: Visibility.PRIVATE 
              }))],
              timeline: [...person.timeline, ...events.map((e: any) => ({ 
                ...e, id: `e_${Math.random()}`, evidenceSessions: [currentSessionId], visibility: Visibility.PRIVATE 
              }))]
            }
          }
        };
      });
    } catch (e) { console.error(e); } finally { setLoading(false); }
  };

  const handleSwitchVisibility = (type: 'wisdom' | 'event', id: string, visibility: Visibility) => {
    setStore(prev => {
      const pId = prev.activePersonId!;
      const person = prev.people[pId];
      if (type === 'wisdom') {
        return {
          ...prev,
          people: {
            ...prev.people,
            [pId]: {
              ...person,
              wisdoms: person.wisdoms.map(w => w.id === id ? { ...w, visibility } : w)
            }
          }
        };
      } else {
        return {
          ...prev,
          people: {
            ...prev.people,
            [pId]: {
              ...person,
              timeline: person.timeline.map(e => e.id === id ? { ...e, visibility } : e)
            }
          }
        };
      }
    });
  };

  const handleLogout = () => {
    setStore(prev => ({ ...prev, activePersonId: null }));
    setStep('intro');
  };

  const renderIntro = () => (
    <div className="flex flex-col items-center justify-center space-y-12 py-10 text-center animate-fade-in">
      <div className="max-w-2xl space-y-6">
        <h2 className="serif text-6xl font-extralight text-stone-900 tracking-tight leading-tight">Harvesting <br/>Life Wisdom.</h2>
        <p className="text-xl text-stone-400 font-light leading-relaxed max-w-lg mx-auto">
          A patient space for older adults to weave their memories into a tapestry for the future.
        </p>
      </div>

      {!activePerson ? (
        <button 
          onClick={() => setStep('identity_select')}
          className="px-12 py-5 bg-stone-900 text-stone-50 rounded-full text-lg font-medium shadow-2xl hover:scale-105 transition-all"
        >
          Begin Journey
        </button>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 w-full max-w-xl pt-10">
          <button onClick={initializeNewSession} className="p-8 bg-stone-900 text-stone-50 rounded-2xl text-center shadow-2xl hover:-translate-y-1 transition-all">
            <span className="block text-xs uppercase tracking-widest opacity-50 mb-2">Preservation</span>
            <span className="text-lg font-medium">Record a New Memory</span>
          </button>
          <button onClick={() => setStep('timeline')} className="p-8 border border-stone-200 bg-white text-stone-700 rounded-2xl text-center shadow-sm hover:-translate-y-1 transition-all">
            <span className="block text-xs uppercase tracking-widest opacity-50 mb-2">Legacy</span>
            <span className="text-lg font-medium">View Memory Archive</span>
          </button>
        </div>
      )}
    </div>
  );

  const renderIdentitySelect = () => {
    const existingPeople = Object.values(store.people);
    return (
      <div className="max-w-2xl mx-auto space-y-12 py-10 animate-fade-in">
        <div className="text-center space-y-4">
          <h2 className="serif text-4xl font-light text-stone-900">Who is telling their story?</h2>
          <p className="text-stone-400 font-light">Select an existing archive or create a new one.</p>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          {existingPeople.map(person => (
            <button 
              key={person.id}
              onClick={() => handleIdentitySelect(person.id)}
              className="p-6 border border-stone-100 bg-white rounded-2xl text-left hover:border-stone-400 transition-all flex items-center justify-between group"
            >
              <div>
                <h3 className="serif text-xl font-medium text-stone-800">{person.displayName}</h3>
                <p className="text-xs text-stone-400 mt-1 uppercase tracking-widest">{person.sessions.length} Memories Harvested</p>
              </div>
              {person.password && <div className="text-stone-200 group-hover:text-stone-400 transition-colors">🔒</div>}
            </button>
          ))}
          <button 
            onClick={() => setStep('identity_init')}
            className="p-6 border border-dashed border-stone-200 bg-stone-50/50 rounded-2xl text-center hover:bg-stone-50 transition-all"
          >
            <span className="text-stone-400 font-medium">+ Create New Archive</span>
          </button>
        </div>
      </div>
    );
  };

  const renderIdentityInit = () => (
