      contents: `I am processing this new memory into the user's archive.
      Known Context: ${context}
      New Memory: ${transcript}

      I need to identify specific life events and abstract wisdoms (beliefs earned through living).
      I also check for conflicts with what I already know.

      Return JSON with "wisdoms", "events", and "conflicts" (any inconsistencies I found).`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            wisdoms: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  belief: { type: Type.STRING },
                  explanation: { type: Type.STRING },
                  confidence: { type: Type.NUMBER }
                },
                required: ["belief", "explanation", "confidence"]
              }
            },
            events: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  event: { type: Type.STRING },
                  timeRange: { type: Type.STRING },
                  phase: { type: Type.STRING, enum: ["Childhood", "Youth", "Adulthood", "Seniority"] },
                  description: { type: Type.STRING },
                  confidence: { type: Type.NUMBER }
                },
                required: ["event", "phase", "confidence"]
              }
            },
            conflicts: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          }
        }
      }
    });
    return JSON.parse(response.text);
  });
};

import React, { useState, useEffect, useRef } from 'react';

interface ListeningModuleProps {
  theme: string;
  onFinish: (transcript: string) => void;
}

const ListeningModule: React.FC<ListeningModuleProps> = ({ theme, onFinish }) => {
  const [isListening, setIsListening] = useState(false);
  const [transcript, setTranscript] = useState('');
  const [volume, setVolume] = useState(0);
  const [inputMode, setInputMode] = useState<'voice' | 'text'>('voice');
  const recognitionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);

  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition && inputMode === 'voice') {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = true;
      recognitionRef.current.interimResults = true;
      recognitionRef.current.lang = navigator.language || 'en-US';

      recognitionRef.current.onresult = (event: any) => {
        let interim = '';
        let final = '';
        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) final += event.results[i][0].transcript;
          else interim += event.results[i][0].transcript;
        }
        if (final) setTranscript(prev => prev + ' ' + final);
      };
      recognitionRef.current.onerror = () => setIsListening(false);
    }
    return () => { if (recognitionRef.current) recognitionRef.current.stop(); };
  }, [inputMode]);

  const startListening = async () => {
    setIsListening(true);
    setTranscript('');
    if (recognitionRef.current) recognitionRef.current.start();
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      const source = audioContextRef.current.createMediaStreamSource(stream);
      analyserRef.current = audioContextRef.current.createAnalyser();
      source.connect(analyserRef.current);
      const dataArray = new Uint8Array(analyserRef.current.frequencyBinCount);
      const updateVolume = () => {
        if (!analyserRef.current) return;
        analyserRef.current.getByteFrequencyData(dataArray);
        setVolume(dataArray.reduce((a, b) => a + b) / dataArray.length);
        if (isListening) requestAnimationFrame(updateVolume);
      };
      updateVolume();
    } catch (err) { console.error(err); }
  };

  const stopListening = () => {
    setIsListening(false);
    if (recognitionRef.current) recognitionRef.current.stop();
    if (audioContextRef.current) audioContextRef.current.close();
    setTimeout(() => onFinish(transcript), 800);
  };

  return (
    <div className="flex flex-col items-center justify-center space-y-8 py-6 animate-fade-in w-full max-w-2xl mx-auto">
      <div className="text-center space-y-2">
        <h2 className="serif text-3xl font-light italic text-stone-800 tracking-tight">I am listening: {theme}</h2>
        <div className="flex justify-center space-x-4">
          <button onClick={() => setInputMode('voice')} className={`text-[10px] uppercase tracking-[0.2em] font-bold ${inputMode === 'voice' ? 'text-stone-900 border-b border-stone-900' : 'text-stone-300'}`}>Voice Mode</button>
          <button onClick={() => setInputMode('text')} className={`text-[10px] uppercase tracking-[0.2em] font-bold ${inputMode === 'text' ? 'text-stone-900 border-b border-stone-900' : 'text-stone-300'}`}>Text Mode</button>
        </div>
      </div>

      {inputMode === 'voice' ? (
        <div className="relative flex items-center justify-center h-64 w-64">
          <div className="absolute inset-0 bg-stone-200 rounded-full transition-all duration-300 ease-out" style={{ transform: `scale(${isListening ? 1 + (volume / 100) * 1.5 : 0.8})`, opacity: isListening ? 0.15 : 0.05 }} />
          <button
            onClick={isListening ? stopListening : startListening}
            className={`relative z-10 w-32 h-32 rounded-full flex flex-col items-center justify-center transition-all duration-700 shadow-xl ${isListening ? 'bg-stone-900' : 'bg-white border border-stone-100'}`}
          >
            {isListening ? <div className="w-8 h-8 bg-white rounded-sm" /> : <div className="w-0 h-0 border-t-[10px] border-t-transparent border-l-[18px] border-l-stone-400 border-b-[10px] border-b-transparent ml-1" />}
          </button>
        </div>
      ) : (
        <textarea 
          value={transcript} 
          onChange={(e) => setTranscript(e.target.value)}
          placeholder="I am ready to read your story... Type here at your own pace."
          className="w-full h-64 p-8 serif text-2xl font-light italic bg-white border border-stone-100 rounded-[2rem] shadow-sm outline-none focus:border-stone-300 transition-colors resize-none"
        />
      )}

      {inputMode === 'text' && (
        <button onClick={() => onFinish(transcript)} disabled={!transcript.trim()} className="px-12 py-3 bg-stone-900 text-white rounded-full font-medium shadow-lg disabled:opacity-20 transition-all">Finished Writing</button>
      )}

      <div className="text-center italic text-stone-400 text-sm serif px-4 h-12">
        {isListening ? "“Take your time. I am recording your words exactly as you speak them.”" : ""}
      </div>
    </div>
  );
};

