              )}
              <button onClick={() => setStep('timeline')} className="w-full py-5 bg-stone-900 text-white rounded-full shadow-2xl font-bold uppercase tracking-[0.2em]">Update My Archive</button>
            </div>
          )}
        </div>
      )}

      {step === 'timeline' && activePerson && (
        <div className="space-y-12 animate-fade-in">
          <div className="flex justify-between items-end border-b border-stone-200 pb-8">
            <h2 className="serif text-5xl font-light">My Life Path</h2>
            <button onClick={initializeNewSession} className="px-6 py-2 bg-stone-900 text-white rounded-full text-xs uppercase tracking-widest font-bold">+ New Memory</button>
          </div>
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
            <div className="lg:col-span-2">
              <TimelineView events={activePerson.timeline} />
            </div>
            <div className="space-y-12">
              <section className="space-y-6">
                <h3 className="text-[10px] font-bold uppercase tracking-widest text-stone-300 border-b border-stone-100 pb-2">{t.wisdom}</h3>
                {activePerson.wisdoms.map((w, i) => (
                  <div key={i} className="wisdom-card p-8 rounded-[2rem] space-y-4">
                    <h4 className="serif text-2xl leading-tight text-stone-800">“{w.belief}”</h4>
                    <p className="text-xs text-stone-400 leading-relaxed italic">{w.explanation}</p>
                    <div className="text-[9px] text-stone-200 uppercase tracking-widest font-bold">Earned: {new Date(w.recordedAt).toLocaleDateString()}</div>
                  </div>
                ))}
              </section>
            </div>
          </div>
        </div>
      )}

      {step === 'search' && activePerson && (
        <div className="max-w-3xl mx-auto space-y-12 animate-fade-in py-10">
          <input type="text" value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} placeholder="Search for memories, names, places..." className="w-full text-4xl serif italic bg-transparent border-b-2 border-stone-100 py-6 outline-none focus:border-stone-900 transition-all" autoFocus />
          <div className="space-y-10">
            {searchQuery && (
              <>
                <section className="space-y-6">
                  <h3 className="text-[10px] uppercase font-bold tracking-[0.3em] text-stone-300">Stories Found</h3>
                  {filteredData.sessions.map(s => (
                    <div key={s.id} className="p-8 bg-white border border-stone-50 rounded-[2rem] shadow-sm">
                      <div className="text-[10px] font-bold uppercase text-stone-300 mb-2">{s.theme} • {new Date(s.timestamp).toLocaleDateString()}</div>
                      <p className="serif text-xl leading-relaxed text-stone-700 italic">"{s.transcript.slice(0, 200)}..."</p>
                    </div>
                  ))}
                </section>
                <section className="space-y-6">
                  <h3 className="text-[10px] uppercase font-bold tracking-[0.3em] text-stone-300">Archive Items Found</h3>
                  {filteredData.timeline.map(e => <div key={e.id} className="serif text-2xl text-stone-800 border-l-2 border-stone-100 pl-6">{e.event}</div>)}
                </section>
              </>
            )}
          </div>
          <div className="flex justify-center">
            <button onClick={() => setStep('intro')} className="text-stone-300 uppercase tracking-widest text-[10px] font-bold">Close Search</button>
          </div>
        </div>
      )}

      {(step === 'identity_select' || step === 'identity_init' || step === 'identity_password') && (
        <div className="py-20 animate-fade-in">
          {step === 'identity_select' && (
             <div className="max-w-2xl mx-auto space-y-12 text-center">
               <h2 className="serif text-4xl font-light">Who is speaking with me?</h2>
               <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                 {(Object.values(store.people) as PersonProfile[]).map(p => (
                   <button key={p.id} onClick={() => handleIdentitySelect(p.id)} className="p-8 border border-stone-100 bg-white rounded-[2rem] hover:border-stone-900 transition-all text-left">
                     <div className="serif text-2xl">{p.displayName}</div>
                     <div className="text-[10px] uppercase font-bold text-stone-300 mt-2">{p.sessions.length} Memories</div>
                   </button>
                 ))}
                 <button onClick={() => setStep('identity_init')} className="p-8 border border-dashed border-stone-200 text-stone-300 rounded-[2rem]">+ New Archive</button>
               </div>
             </div>
          )}
          {step === 'identity_init' && (
            <div className="max-w-md mx-auto space-y-8 text-center">
              <h2 className="serif text-4xl font-light">What name shall I remember?</h2>
              <input type="text" value={nameInput} onChange={(e) => setNameInput(e.target.value)} className="w-full bg-transparent border-b-2 border-stone-100 py-4 text-3xl serif text-center outline-none focus:border-stone-900" autoFocus />
              <button onClick={() => { if(nameInput) handleIdentityCreate(); }} className="px-14 py-4 bg-stone-900 text-white rounded-full">Begin My Archive</button>
            </div>
          )}
          {/* Fix: Added UI for identity_password step */}
          {step === 'identity_password' && (
            <div className="max-w-md mx-auto space-y-8 text-center">
              <h2 className="serif text-4xl font-light">Whisper your password...</h2>
              <input 
                type="password" 
                value={passwordInput} 
                onChange={(e) => setPasswordInput(e.target.value)} 
                onKeyDown={(e) => e.key === 'Enter' && handlePasswordSubmit()}
                className="w-full bg-transparent border-b-2 border-stone-100 py-4 text-3xl serif text-center outline-none focus:border-stone-900" 
                autoFocus 
              />
              <div className="flex justify-center space-x-4">
                <button onClick={handlePasswordSubmit} className="px-14 py-4 bg-stone-900 text-white rounded-full">Open Archive</button>
                <button onClick={() => setStep('identity_select')} className="px-10 py-4 border border-stone-200 rounded-full">Back</button>
              </div>
            </div>
          )}
        </div>
      )}
    </Layout>
  );
};

