      setAiDecision(result);
      if (result.decision === 'accept') { finalizeSession(transcript); } 
      else { setStep('reflect'); }
    } catch (e) { 
      console.error("Analysis failed:", e);
      finalizeSession(transcript); 
    } finally { 
      setLoading(false); 
    }
  };

