import { GoogleGenAI, Type } from "@google/genai";
import { LifePhase, TimelineEvent, LifeWisdom } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

async function executeWithRetry<T>(operation: () => Promise<T>, maxRetries: number = 3): Promise<T> {
  let lastError: any;
  for (let attempt = 0; attempt < maxRetries; attempt++) {
    try {
      return await operation();
    } catch (error: any) {
      lastError = error;
      const errorMessage = error?.message || "";
      const isOverloaded = errorMessage.includes("503") || errorMessage.toLowerCase().includes("overloaded");
      if (isOverloaded) {
        const delay = Math.pow(2, attempt + 1) * 1000 + Math.random() * 1000;
        await new Promise(resolve => setTimeout(resolve, delay));
        continue;
      }
      throw error;
    }
  }
  throw lastError;
}

export const distillStory = async (transcript: string, theme: string) => {
  return executeWithRetry(async () => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are I, the user's personal oral historian and narrator. 
      I am helping the user preserve their story about "${theme}".

      User's words: "${transcript}"

      As "I", transform this transcript into a coherent first-person story. 
      Maintain the user's soul, cultural rhythm, and original language mix. 
      I should remove fillers but keep the "heart" of the narrative.`,
      config: { temperature: 0.4 }
    });
    return response.text;
  });
};

export const analyzeNarrativeDepth = async (transcript: string, theme: string) => {
  return executeWithRetry(async () => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `I am listening to the user's story about "${theme}".
      Current Transcript: "${transcript}"

      I need to decide:
      1. "ask_clarify": I hear the story but want to know more details to really remember it right. I will ask a gentle question as "I".
      2. "accept": I have heard a beautiful and complete memory.
      3. "abstain": I didn't quite catch a story here.

      Return JSON with "decision" and "message" (my gentle question if decision is ask_clarify). Use "I" in the message.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            decision: { type: Type.STRING, enum: ["ask_clarify", "accept", "abstain"] },
            message: { type: Type.STRING }
          },
          required: ["decision"]
        }
      }
    });
    return JSON.parse(response.text);
  });
};

export const extractLifeStructure = async (transcript: string, context: string) => {
  return executeWithRetry(async () => {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `I am processing this new memory into the user's archive.
      Known Context: ${context}
      New Memory: ${transcript}

      I need to identify specific life events and abstract wisdoms (beliefs earned through living).
      IMPORTANT: For "phase", you MUST use exactly one of these strings: "Childhood", "Youth", "Adulthood", "Seniority".

      Return JSON with "wisdoms", "events", and "conflicts" (any inconsistencies I found).`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            wisdoms: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  belief: { type: Type.STRING },
                  explanation: { type: Type.STRING },
                  confidence: { type: Type.NUMBER }
                },
                required: ["belief", "explanation", "confidence"]
              }
            },
            events: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  event: { type: Type.STRING },
                  timeRange: { type: Type.STRING },
                  phase: { type: Type.STRING },
                  description: { type: Type.STRING },
                  confidence: { type: Type.NUMBER }
                },
                required: ["event", "phase", "confidence"]
              }
            },
            conflicts: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          }
        }
      }
    });
    return JSON.parse(response.text);
  });
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import Layout from './components/Layout';
import ListeningModule from './components/ListeningModule';
import TimelineView from './components/TimelineView';
import { 
  Step, 
  LifeMemoryStore, 
  MemorySession, 
  LifePhase, 
  TimelineEvent, 
  LifeWisdom,
  PersonProfile,
  Visibility,
  Language
} from './types';
import { 
  distillStory, 
  extractLifeStructure, 
  analyzeNarrativeDepth 
} from './services/geminiService';

const STORAGE_KEY = 'project_vibe_multi_identity_v2';

const App: React.FC = () => {
  const [step, setStep] = useState<Step>('cover');
  const [loading, setLoading] = useState(false);
  const [currentSessionId, setCurrentSessionId] = useState<string>('');
  const [currentTheme, setCurrentTheme] = useState('');
  const [newThemeInput, setNewThemeInput] = useState('');
  const [currentTranscript, setCurrentTranscript] = useState('');
  const [aiDecision, setAiDecision] = useState<{decision: string, message?: string} | null>(null);
  const [distilledPreview, setDistilledPreview] = useState<string>('');
  const [saveOption, setSaveOption] = useState<'original' | 'polished'>('polished');
  const [searchQuery, setSearchQuery] = useState('');
  const [uiLang, setUiLang] = useState<Language>('en');

  const [nameInput, setNameInput] = useState('');
  const [passwordInput, setPasswordInput] = useState('');
  const [targetPersonId, setTargetPersonId] = useState<string | null>(null);
  const [isExitingCover, setIsExitingCover] = useState(false);
  const [conflicts, setConflicts] = useState<string[]>([]);

  const [store, setStore] = useState<LifeMemoryStore>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      return saved ? JSON.parse(saved) : { activePersonId: null, people: {} };
    } catch (e) {
      console.error("Failed to load store:", e);
      return { activePersonId: null, people: {} };
    }
  });

  const activePerson: PersonProfile | null = store.activePersonId ? store.people[store.activePersonId] : null;

  useEffect(() => {
    const handler = setTimeout(() => {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(store));
    }, 1000);
    return () => clearTimeout(handler);
  }, [store]);

  const defaultThemes = [
    "A memory from childhood", "A memory about family and home",
    "A memory about an important choice", "A memory about a difficult time",
    "A memory about a life lesson", "A memory about a turning point",
    "A memory about something I miss", "A memory about a challenge I overcame"
  ];

  const initializeNewSession = () => {
    const id = `sess_${Date.now()}`;
    setCurrentSessionId(id);
    setStep('theme');
  };

  const handleFinishListening = async (transcript: string) => {
    setCurrentTranscript(transcript);
    if (!transcript.trim()) return;
    setLoading(true);
    try {
      const result = await analyzeNarrativeDepth(transcript, currentTheme);
      setAiDecision(result);
      if (result.decision === 'accept') { 
        finalizeSession(transcript); 
      } else { 
        setStep('reflect'); 
      }
    } catch (e) { 
      console.error("Analysis failed, proceeding to finalize anyway:", e);
      finalizeSession(transcript); 
    } finally { 
      setLoading(false); 
    }
  };

  const finalizeSession = async (transcript: string) => {
    const pId = store.activePersonId;
    if (!pId || !store.people[pId]) return;

    setLoading(true);
    setStep('distill');

    try {
      // 1. Distill the story (The "I" polished version)
      const distilled = await distillStory(transcript, currentTheme);
      setDistilledPreview(distilled || transcript);

      // 2. Extract structure (Timeline & Wisdom)
      const person = store.people[pId];
      const contextStr = (person.timeline || []).map(e => `${e.phase}: ${e.event}`).join(', ');

      const extraction = await extractLifeStructure(transcript, contextStr);
      let wisdoms = extraction?.wisdoms || [];
      let events = extraction?.events || [];
      const foundConflicts = extraction?.conflicts || [];

      setConflicts(foundConflicts);

      // 3. Fallback: If AI fails to find an event, create one from the theme
      if (events.length === 0 && transcript.length > 50) {
        events = [{
          event: currentTheme,
          phase: "Seniority", // Default for recorded memories
          description: transcript.slice(0, 100) + "...",
          confidence: 0.5,
          timeRange: "Recent Record"
        }];
      }

      const newSession: MemorySession = {
        id: currentSessionId,
        timestamp: Date.now(),
        theme: currentTheme,
        transcript: transcript,
        polishedTranscript: distilled,
        status: 'completed'
      };

      // 4. Update the centralized store
      setStore(prev => {
        const target = prev.people[pId];
        if (!target) return prev;

        const updatedTimeline = [
          ...(target.timeline || []),
          ...events.map((e: any) => ({
            ...e,
            id: `e_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
            recordedAt: Date.now(),
            evidenceSessions: [currentSessionId],
            visibility: Visibility.PRIVATE
          }))
        ];

        const updatedWisdoms = [
          ...(target.wisdoms || []),
          ...wisdoms.map((w: any) => ({
            ...w,
            id: `w_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
            recordedAt: Date.now(),
            evidenceSessions: [currentSessionId],
            visibility: Visibility.PRIVATE
          }))
        ];

        return {
          ...prev,
          people: {
            ...prev.people,
            [pId]: {
              ...target,
              sessions: [...(target.sessions || []), newSession],
              timeline: updatedTimeline,
              wisdoms: updatedWisdoms
            }
          }
        };
      });
    } catch (e) { 
      console.error("Critical error in finalization:", e);
    } finally { 
      setLoading(false); 
    }
  };

  const handleIdentitySelect = (personId: string) => {
    const person = store.people[personId];
    if (person.password) { setTargetPersonId(personId); setStep('identity_password'); } 
    else { setStore(prev => ({ ...prev, activePersonId: personId })); setStep('intro'); }
  };

  const handleIdentityCreate = () => {
    if (!nameInput.trim()) return;
    const newId = `person_${Date.now()}`;
    const newPerson: PersonProfile = {
      id: newId,
      displayName: nameInput,
      sessions: [],
      timeline: [],
      wisdoms: []
    };
    setStore(prev => ({
      ...prev,
      activePersonId: newId,
      people: {
        ...prev.people,
        [newId]: newPerson
      }
    }));
    setNameInput('');
    setStep('intro');
  };

  const handlePasswordSubmit = () => {
    if (!targetPersonId) return;
    const person = store.people[targetPersonId];
    if (person.password === passwordInput) {
      setStore(prev => ({ ...prev, activePersonId: targetPersonId }));
      setStep('intro');
      setPasswordInput('');
      setTargetPersonId(null);
    } else {
      alert("Incorrect password");
    }
  };

  const handleLogout = () => { setStore(prev => ({ ...prev, activePersonId: null })); setStep('cover'); };

  const handleExport = () => {
    if (!activePerson) return;
    const blob = new Blob([JSON.stringify(activePerson, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${activePerson.displayName}_Archive.json`;
    a.click();
  };

  const filteredData = useMemo(() => {
    if (!activePerson || !searchQuery) return { sessions: [], timeline: [], wisdoms: [] };
    const q = searchQuery.toLowerCase();
    return {
      sessions: (activePerson.sessions || []).filter(s => s.transcript.toLowerCase().includes(q) || s.theme.toLowerCase().includes(q)),
      timeline: (activePerson.timeline || []).filter(e => e.event.toLowerCase().includes(q) || e.description.toLowerCase().includes(q)),
      wisdoms: (activePerson.wisdoms || []).filter(w => w.belief.toLowerCase().includes(q) || w.explanation.toLowerCase().includes(q))
    };
  }, [activePerson, searchQuery]);

  const t = {
    en: { open: "Open the book", record: "Record a Memory", archive: "View Archive", switch: "Switch Person", wisdom: "Life Wisdom", search: "Search Memories", export: "Export Archive" },
    zh: { open: "翻开书卷", record: "记录一段回忆", archive: "查看档案", switch: "切换账号", wisdom: "人生智慧", search: "搜索记忆", export: "导出档案" },
    es: { open: "Abrir el libro", record: "Grabar un recuerdo", archive: "Ver archivo", switch: "Cambiar persona", wisdom: "Sabiduría de vida", search: "Buscar memorias", export: "Exportar archivo" }
  }[uiLang];

  return (
    <Layout 
      onHomeClick={() => setStep(activePerson ? 'intro' : 'cover')}
      subtitle={activePerson ? (
        <div className="flex flex-col space-y-2">
          <div className="flex items-center space-x-4">
            <span className="font-light italic text-stone-400 text-xs">Archiving: {activePerson.displayName}</span>
            <button onClick={handleLogout} className="text-[10px] uppercase font-bold tracking-widest text-stone-300 hover:text-stone-900 border-l border-stone-200 pl-4">{t.switch} 🔁</button>
            <div className="flex space-x-2 border-l border-stone-200 pl-4">
              {['en', 'zh', 'es'].map(l => (
                <button key={l} onClick={() => setUiLang(l as Language)} className={`text-[10px] uppercase font-bold ${uiLang === l ? 'text-stone-900' : 'text-stone-200'}`}>{l}</button>
              ))}
            </div>
          </div>
        </div>
      ) : undefined}
    >
      {step === 'cover' && (
        <div className={`flex flex-col items-center justify-center min-h-[70vh] cursor-pointer transition-all duration-700 ${isExitingCover ? 'page-turn-exit' : 'animate-fade-in'}`} onClick={() => { setIsExitingCover(true); setTimeout(() => { setStep(activePerson ? 'intro' : 'identity_select'); setIsExitingCover(false); }, 800); }}>
          <div className="w-full max-w-sm aspect-[3/4] bg-[#fcfaf2] border border-stone-200 rounded-lg book-shadow flex flex-col items-center justify-between p-12 text-center relative group">
            <div className="absolute left-0 top-0 bottom-0 w-6 border-r border-stone-100 bg-stone-50/30 rounded-l-lg" />
            <div className="pt-12 space-y-4">
              <h1 className="serif text-5xl font-light text-stone-900 leading-tight">Echoes <br/> of a Life</h1>
            </div>
            <div className="pb-12 space-y-6">
              <p className="text-stone-400 font-light italic text-sm">Your stories matter.<br/>Take your time.</p>
              <div className="text-[10px] uppercase font-bold tracking-[0.4em] text-stone-300 group-hover:text-stone-900">{t.open}</div>
            </div>
          </div>
        </div>
      )}

      {step === 'intro' && (
        <div className="flex flex-col items-center justify-center space-y-12 py-10 animate-fade-in">
          <div className="max-w-2xl text-center space-y-4">
            <h2 className="serif text-6xl font-extralight text-stone-900">I am here to listen.</h2>
            <p className="text-xl text-stone-400 font-light">I am your narrative companion. I remember everything you tell me.</p>
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 w-full max-w-2xl">
            <button onClick={initializeNewSession} className="p-10 bg-stone-900 text-stone-50 rounded-[2rem] shadow-xl hover:-translate-y-1 transition-all">{t.record}</button>
            <button onClick={() => setStep('timeline')} className="p-10 border border-stone-200 bg-white text-stone-700 rounded-[2rem] hover:-translate-y-1 transition-all">{t.archive}</button>
            <button onClick={() => setStep('search')} className="p-6 border border-stone-100 bg-stone-50/30 rounded-2xl text-stone-400 text-sm">{t.search} 🔍</button>
            <button onClick={handleExport} className="p-6 border border-stone-100 bg-stone-50/30 rounded-2xl text-stone-400 text-sm">{t.export} ⬇️</button>
          </div>
        </div>
      )}

      {step === 'theme' && (
        <div className="space-y-10 animate-fade-in">
          <div className="text-center">
            <h2 className="serif text-4xl font-light">What shall we talk about?</h2>
          </div>
          <div className="flex flex-wrap justify-center gap-3 max-w-3xl mx-auto">
            {defaultThemes.map(th => (
              <button key={th} onClick={() => { setCurrentTheme(th); setStep('listen'); }} className="px-6 py-2 rounded-full border border-stone-200 text-sm hover:border-stone-900 transition-colors">{th}</button>
            ))}
            <div className="flex items-center space-x-2 w-full max-w-md mt-4">
              <input type="text" value={newThemeInput} onChange={(e) => setNewThemeInput(e.target.value)} placeholder="+ Create a custom theme..." className="flex-grow bg-transparent border-b border-stone-200 py-2 outline-none serif italic" />
              <button onClick={() => { if(newThemeInput) { setCurrentTheme(newThemeInput); setStep('listen'); } }} className="text-stone-900 font-bold uppercase text-[10px] tracking-widest">Begin</button>
            </div>
          </div>
        </div>
      )}

      {step === 'listen' && <ListeningModule theme={currentTheme} onFinish={handleFinishListening} />}

      {step === 'reflect' && (
        <div className="max-w-2xl mx-auto py-12 text-center space-y-10">
          <h2 className="serif text-4xl font-light italic">"I hear what you're saying..."</h2>
          <div className="p-10 bg-white border border-stone-100 rounded-[3rem] shadow-sm serif text-3xl leading-relaxed">
            {aiDecision?.message}
          </div>
          <div className="flex justify-center space-x-6">
            <button onClick={() => setStep('listen')} className="px-10 py-4 bg-stone-900 text-white rounded-full">Tell me more</button>
            <button onClick={() => finalizeSession(currentTranscript)} className="px-10 py-4 border border-stone-200 rounded-full">No, that is all</button>
          </div>
        </div>
      )}

      {step === 'distill' && (
        <div className="max-w-3xl mx-auto py-10 space-y-12">
          {loading ? (
            <div className="flex flex-col items-center justify-center py-20 space-y-4">
              <div className="w-12 h-12 border-4 border-stone-100 border-t-stone-900 rounded-full animate-spin"></div>
              <div className="serif italic text-2xl text-stone-400">I am carefully weaving your story into the archive...</div>
            </div>
          ) : (
            <div className="space-y-8 animate-fade-in">
              <div className="flex items-center justify-between border-b border-stone-100 pb-4">
                <span className="text-[10px] uppercase font-bold tracking-[0.4em] text-stone-300">Memory Preserved</span>
                <div className="flex space-x-4">
                  <button onClick={() => setSaveOption('polished')} className={`text-[10px] uppercase font-bold ${saveOption === 'polished' ? 'text-stone-900' : 'text-stone-300'}`}>I prefer polished</button>
                  <button onClick={() => setSaveOption('original')} className={`text-[10px] uppercase font-bold ${saveOption === 'original' ? 'text-stone-900' : 'text-stone-300'}`}>Keep it raw</button>
                </div>
              </div>
              <p className="serif text-4xl font-extralight text-stone-800 leading-snug italic whitespace-pre-wrap">
                {saveOption === 'polished' ? distilledPreview : currentTranscript}
              </p>
              {conflicts.length > 0 && (
                <div className="p-6 bg-amber-50 rounded-2xl border border-amber-100 space-y-2">
                  <p className="text-[10px] uppercase font-bold tracking-widest text-amber-600">I noticed something curious:</p>
                  {conflicts.map((c, i) => <p key={i} className="text-sm text-amber-800 italic">"I recall a different detail previously: {c}"</p>)}
                </div>
              )}
              <div className="flex flex-col space-y-4 pt-8">
                <button onClick={() => setStep('timeline')} className="w-full py-5 bg-stone-900 text-white rounded-full shadow-2xl font-bold uppercase tracking-[0.2em] hover:bg-stone-800 transition-colors">See my Life Path updated</button>
                <p className="text-center text-[10px] text-stone-400 uppercase tracking-widest font-bold animate-pulse">Archive complete. I have saved your words.</p>
              </div>
            </div>
          )}
        </div>
      )}

      {step === 'timeline' && activePerson && (
        <div className="space-y-12 animate-fade-in">
          <div className="flex justify-between items-end border-b border-stone-200 pb-8">
            <h2 className="serif text-5xl font-light">My Life Path</h2>
            <button onClick={initializeNewSession} className="px-6 py-2 bg-stone-900 text-white rounded-full text-xs uppercase tracking-widest font-bold">+ Record a Memory</button>
          </div>
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
            <div className="lg:col-span-2">
              <TimelineView events={activePerson.timeline || []} />
            </div>
            <div className="space-y-12">
              <section className="space-y-6">
                <h3 className="text-[10px] font-bold uppercase tracking-widest text-stone-300 border-b border-stone-100 pb-2">{t.wisdom}</h3>
                {(activePerson.wisdoms || []).map((w, i) => (
                  <div key={w.id || `w-${i}`} className="wisdom-card p-8 rounded-[2rem] space-y-4 animate-fade-in" style={{animationDelay: `${i*100}ms`}}>
                    <h4 className="serif text-2xl leading-tight text-stone-800">“{w.belief}”</h4>
                    <p className="text-xs text-stone-400 leading-relaxed italic">{w.explanation}</p>
                    <div className="text-[9px] text-stone-200 uppercase tracking-widest font-bold">Earned: {new Date(w.recordedAt).toLocaleDateString()}</div>
                  </div>
                ))}
              </section>
            </div>
          </div>
        </div>
      )}

      {step === 'search' && activePerson && (
        <div className="max-w-3xl mx-auto space-y-12 animate-fade-in py-10">
          <input type="text" value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} placeholder="Search for memories, names, places..." className="w-full text-4xl serif italic bg-transparent border-b-2 border-stone-100 py-6 outline-none focus:border-stone-900 transition-all" autoFocus />
          <div className="space-y-10">
            {searchQuery && (
              <>
                <section className="space-y-6">
                  <h3 className="text-[10px] uppercase font-bold tracking-[0.3em] text-stone-300">Stories Found</h3>
                  {filteredData.sessions.map(s => (
                    <div key={s.id} className="p-8 bg-white border border-stone-50 rounded-[2rem] shadow-sm">
                      <div className="text-[10px] font-bold uppercase text-stone-300 mb-2">{s.theme} • {new Date(s.timestamp).toLocaleDateString()}</div>
                      <p className="serif text-xl leading-relaxed text-stone-700 italic">"{s.transcript.slice(0, 200)}..."</p>
                    </div>
                  ))}
                </section>
                <section className="space-y-6">
                  <h3 className="text-[10px] uppercase font-bold tracking-[0.3em] text-stone-300">Archive Items Found</h3>
                  {filteredData.timeline.map(e => <div key={e.id} className="serif text-2xl text-stone-800 border-l-2 border-stone-100 pl-6">{e.event}</div>)}
                </section>
              </>
            )}
          </div>
          <div className="flex justify-center">
            <button onClick={() => setStep('intro')} className="text-stone-300 uppercase tracking-widest text-[10px] font-bold hover:text-stone-900 transition-colors">Close Search</button>
          </div>
        </div>
      )}

      {(step === 'identity_select' || step === 'identity_init' || step === 'identity_password') && (
        <div className="py-20 animate-fade-in">
          {step === 'identity_select' && (
             <div className="max-w-2xl mx-auto space-y-12 text-center">
               <h2 className="serif text-4xl font-light text-stone-900">Who is speaking with me?</h2>
               <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                 {(Object.values(store.people) as PersonProfile[]).map(p => (
                   <button key={p.id} onClick={() => handleIdentitySelect(p.id)} className="p-8 border border-stone-100 bg-white rounded-[2rem] hover:border-stone-900 transition-all text-left group">
                     <div className="serif text-2xl text-stone-800 group-hover:text-stone-900">{p.displayName}</div>
                     <div className="text-[10px] uppercase font-bold text-stone-300 mt-2">{p.sessions?.length || 0} Memories archived</div>
                   </button>
                 ))}
                 <button onClick={() => setStep('identity_init')} className="p-8 border border-dashed border-stone-200 text-stone-300 hover:text-stone-500 hover:border-stone-400 rounded-[2rem] transition-all">+ Create a New Archive</button>
               </div>
             </div>
          )}
          {step === 'identity_init' && (
            <div className="max-w-md mx-auto space-y-8 text-center">
              <h2 className="serif text-4xl font-light">What name shall I remember?</h2>
              <input type="text" value={nameInput} onChange={(e) => setNameInput(e.target.value)} className="w-full bg-transparent border-b-2 border-stone-100 py-4 text-3xl serif text-center outline-none focus:border-stone-900" autoFocus />
              <div className="flex flex-col space-y-4">
                <button onClick={() => { if(nameInput) handleIdentityCreate(); }} className="px-14 py-4 bg-stone-900 text-white rounded-full font-bold uppercase tracking-widest text-xs">Begin My Archive</button>
                <button onClick={() => setStep('identity_select')} className="text-[10px] uppercase font-bold text-stone-300">Back</button>
              </div>
            </div>
          )}
          {step === 'identity_password' && (
            <div className="max-w-md mx-auto space-y-8 text-center">
              <h2 className="serif text-4xl font-light">Whisper your password...</h2>
              <input 
                type="password" 
                value={passwordInput} 
                onChange={(e) => setPasswordInput(e.target.value)} 
                onKeyDown={(e) => e.key === 'Enter' && handlePasswordSubmit()}
                className="w-full bg-transparent border-b-2 border-stone-100 py-4 text-3xl serif text-center outline-none focus:border-stone-900" 
                autoFocus 
              />
              <div className="flex justify-center space-x-4">
                <button onClick={handlePasswordSubmit} className="px-14 py-4 bg-stone-900 text-white rounded-full">Open Archive</button>
                <button onClick={() => { setStep('identity_select'); setTargetPersonId(null); setPasswordInput(''); }} className="px-10 py-4 border border-stone-200 rounded-full">Back</button>
              </div>
            </div>
          )}
        </div>
      )}
    </Layout>
  );
};

export default App;

import React from 'react';
import { TimelineEvent, LifePhase } from '../types';

interface TimelineViewProps {
  events: TimelineEvent[];
}

const TimelineView: React.FC<TimelineViewProps> = ({ events }) => {
  // 恢复到最可靠的排序逻辑
  const sortedEvents = [...events].sort((a, b) => {
    const order = ['Childhood', 'Youth', 'Adulthood', 'Seniority'];

    // 兼容处理：确保 phase 字符串与排序数组匹配
    const getOrder = (phase: string) => {
      const p = phase?.charAt(0).toUpperCase() + phase?.slice(1).toLowerCase();
      const index = order.indexOf(p);
      return index === -1 ? 99 : index;
    };

    const orderA = getOrder(a.phase as string);
    const orderB = getOrder(b.phase as string);

    if (orderA !== orderB) return orderA - orderB;
    return (a.recordedAt || 0) - (b.recordedAt || 0);
  });

  return (
    <div className="relative py-10 pl-8 space-y-12 animate-fade-in">
      {/* 主时间轴线 */}
      <div className="absolute left-[3.5px] top-0 bottom-0 w-[1px] bg-stone-200" />

      {sortedEvents.map((event, idx) => (
        <div key={event.id || idx} className="relative group">
          {/* 时间轴节点 */}
          <div className="absolute left-[-32.5px] top-1.5 w-4 h-4 rounded-full border-2 border-[#fdfcf8] bg-stone-300 group-hover:bg-stone-900 group-hover:scale-125 transition-all duration-300" />

          <div className="space-y-2">
            <div className="flex items-center justify-between">
              <span className="text-[9px] font-bold uppercase tracking-widest text-stone-400 group-hover:text-stone-900 transition-colors">
                {event.phase} {event.timeRange ? `• ${event.timeRange}` : ''}
              </span>
              <span className="text-[9px] text-stone-300 italic font-medium">
                记录于: {new Date(event.recordedAt).toLocaleDateString()}
              </span>
            </div>
            <h3 className="serif text-2xl font-medium text-stone-900 leading-tight">{event.event}</h3>
            <p className="text-stone-500 font-light leading-relaxed max-w-2xl serif italic opacity-80 group-hover:opacity-100 transition-opacity">
              {event.description}
            </p>
          </div>
        </div>
      ))}

      {sortedEvents.length === 0 && (
        <div className="text-stone-300 italic font-light py-20 text-center w-full serif text-xl">
          您的生命足迹将随着我们的交谈慢慢浮现。
        </div>
      )}
    </div>
  );
};

