import { 
  Step, 
  LifeMemoryStore, 
  MemorySession, 
  LifePhase, 
  TimelineEvent, 
  LifeWisdom,
  PersonProfile,
  Visibility,
  Language
} from './types';
import { 
  distillStory, 
  extractLifeStructure, 
  analyzeNarrativeDepth 
} from './services/geminiService';

const STORAGE_KEY = 'life_echoes_store_v1';

const App: React.FC = () => {
  const [step, setStep] = useState<Step>('cover');
  const [loading, setLoading] = useState(false);
  const [currentSessionId, setCurrentSessionId] = useState<string>('');
  const [currentTheme, setCurrentTheme] = useState('');
  const [newThemeInput, setNewThemeInput] = useState('');
  const [currentTranscript, setCurrentTranscript] = useState('');
  const [aiDecision, setAiDecision] = useState<{decision: string, message?: string} | null>(null);
  const [distilledPreview, setDistilledPreview] = useState<string>('');
  const [saveOption, setSaveOption] = useState<'original' | 'polished'>('polished');
  const [searchQuery, setSearchQuery] = useState('');
  const [uiLang, setUiLang] = useState<Language>('zh');

  const [nameInput, setNameInput] = useState('');
  const [passwordInput, setPasswordInput] = useState('');
  const [targetPersonId, setTargetPersonId] = useState<string | null>(null);
  const [isExitingCover, setIsExitingCover] = useState(false);
  const [conflicts, setConflicts] = useState<string[]>([]);

  const [store, setStore] = useState<LifeMemoryStore>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      return saved ? JSON.parse(saved) : { activePersonId: null, people: {} };
    } catch (e) {
      return { activePersonId: null, people: {} };
    }
  });

  const activePerson = store.activePersonId ? store.people[store.activePersonId] : null;

  // 优化：只有在 store 真正变化且不在加载状态时才保存，减少卡顿
  useEffect(() => {
    if (store.activePersonId || Object.keys(store.people).length > 0) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(store));
    }
  }, [store]);

  const defaultThemes = [
    "童年的一个回忆", "关于家庭和故乡的往事",
    "一个重要的人生长择", "一次艰难但难忘的时光",
    "生活教会我的道理", "命运的转折点",
    "一些我非常怀念的事物", "我曾经克服过的一次挑战"
  ];

  const initializeNewSession = () => {
    const id = `sess_${Date.now()}`;
    setCurrentSessionId(id);
    setStep('theme');
  };

  const handleFinishListening = async (transcript: string) => {
    setCurrentTranscript(transcript);
    if (!transcript.trim()) return;
    setLoading(true);
    try {
      const result = await analyzeNarrativeDepth(transcript, currentTheme);
      setAiDecision(result);
      if (result.decision === 'accept') { 
        finalizeSession(transcript); 
      } else { 
        setStep('reflect'); 
      }
    } catch (e) { 
      finalizeSession(transcript); 
    } finally { 
      setLoading(false); 
    }
  };

  const finalizeSession = async (transcript: string) => {
    const pId = store.activePersonId;
    if (!pId || !store.people[pId]) return;

    setLoading(true);
    setStep('distill');

    try {
      const distilled = await distillStory(transcript, currentTheme);
      setDistilledPreview(distilled || transcript);

      const person = store.people[pId];
      const contextStr = (person.timeline || []).map(e => `${e.phase}: ${e.event}`).join(', ');

      const extraction = await extractLifeStructure(transcript, contextStr);
      let wisdoms = extraction?.wisdoms || [];
      let events = extraction?.events || [];

      setConflicts(extraction?.conflicts || []);

      // 强制兜底：如果没有提取到事件，则自动生成一个
      if (events.length === 0) {
        events = [{
          event: currentTheme,
          phase: "Seniority",
          description: transcript.slice(0, 150) + "...",
          confidence: 1,
          timeRange: "记录时间"
        }];
      }

      const newSession: MemorySession = {
        id: currentSessionId,
        timestamp: Date.now(),
        theme: currentTheme,
        transcript: transcript,
        polishedTranscript: distilled,
        status: 'completed'
      };

      setStore(prev => {
        const target = prev.people[pId];
        if (!target) return prev;

        const newEvents = events.map((e: any) => ({
          ...e,
          id: `e_${Date.now()}_${Math.random().toString(36).substr(2, 5)}`,
          recordedAt: Date.now(),
          evidenceSessions: [currentSessionId],
          visibility: Visibility.PRIVATE
        }));

        const newWisdoms = wisdoms.map((w: any) => ({
          ...w,
          id: `w_${Date.now()}_${Math.random().toString(36).substr(2, 5)}`,
          recordedAt: Date.now(),
          evidenceSessions: [currentSessionId],
          visibility: Visibility.PRIVATE
        }));

        return {
          ...prev,
          people: {
            ...prev.people,
            [pId]: {
              ...target,
              sessions: [...(target.sessions || []), newSession],
              timeline: [...(target.timeline || []), ...newEvents],
              wisdoms: [...(target.wisdoms || []), ...newWisdoms]
            }
          }
        };
      });
    } catch (e) { 
      console.error(e);
    } finally { 
      setLoading(false); 
    }
  };

  const handleIdentitySelect = (personId: string) => {
    const person = store.people[personId];
    if (person.password) { setTargetPersonId(personId); setStep('identity_password'); } 
    else { setStore(prev => ({ ...prev, activePersonId: personId })); setStep('intro'); }
  };

  const handleIdentityCreate = () => {
    if (!nameInput.trim()) return;
    const newId = `person_${Date.now()}`;
    const newPerson: PersonProfile = {
      id: newId, displayName: nameInput, sessions: [], timeline: [], wisdoms: []
    };
    setStore(prev => ({
      ...prev, activePersonId: newId, people: { ...prev.people, [newId]: newPerson }
    }));
    setNameInput('');
    setStep('intro');
  };

  const handlePasswordSubmit = () => {
    if (!targetPersonId) return;
    const person = store.people[targetPersonId];
    if (person.password === passwordInput) {
      setStore(prev => ({ ...prev, activePersonId: targetPersonId }));
      setStep('intro');
      setPasswordInput('');
      setTargetPersonId(null);
    } else {
      alert("密码错误");
    }
  };

  const handleLogout = () => { 
    setStore(prev => ({ ...prev, activePersonId: null })); 
    setStep('cover'); 
  };

  const filteredData = useMemo(() => {
    if (!activePerson || !searchQuery) return { sessions: [], timeline: [], wisdoms: [] };
    const q = searchQuery.toLowerCase();
    return {
      sessions: (activePerson.sessions || []).filter(s => s.transcript.toLowerCase().includes(q)),
      timeline: (activePerson.timeline || []).filter(e => e.event.toLowerCase().includes(q)),
      wisdoms: (activePerson.wisdoms || []).filter(w => w.belief.toLowerCase().includes(q))
    };
  }, [activePerson, searchQuery]);

  const t = {
    en: { open: "Open the book", record: "Record a Memory", archive: "View Archive", switch: "Switch Person", wisdom: "Life Wisdom", search: "Search Memories", export: "Export Archive" },
    zh: { open: "翻开书卷", record: "记录一段回忆", archive: "查看档案", switch: "切换账号", wisdom: "人生智慧", search: "搜索记忆", export: "导出档案" },
    es: { open: "Abrir el libro", record: "Grabar un recuerdo", archive: "Ver archivo", switch: "Cambiar persona", wisdom: "Sabiduría de vida", search: "Buscar memorias", export: "Exportar archivo" }
  }[uiLang];

  return (
    <Layout 
      onHomeClick={() => setStep(activePerson ? 'intro' : 'cover')}
      subtitle={activePerson ? (
        <div className="flex items-center space-x-4">
          <span className="font-light italic text-stone-400 text-xs">正在为 {activePerson.displayName} 记录</span>
          <button onClick={handleLogout} className="text-[10px] uppercase font-bold tracking-widest text-stone-300 hover:text-stone-900 border-l border-stone-200 pl-4">{t.switch} 🔁</button>
          <div className="flex space-x-2 border-l border-stone-200 pl-4">
            {['en', 'zh', 'es'].map(l => (
              <button key={l} onClick={() => setUiLang(l as Language)} className={`text-[10px] uppercase font-bold ${uiLang === l ? 'text-stone-900' : 'text-stone-200'}`}>{l}</button>
            ))}
          </div>
        </div>
      ) : undefined}
    >
      {step === 'cover' && (
        <div className={`flex flex-col items-center justify-center min-h-[70vh] cursor-pointer transition-all duration-700 ${isExitingCover ? 'page-turn-exit' : 'animate-fade-in'}`} onClick={() => { setIsExitingCover(true); setTimeout(() => { setStep(activePerson ? 'intro' : 'identity_select'); setIsExitingCover(false); }, 800); }}>
          <div className="w-full max-w-sm aspect-[3/4] bg-[#fcfaf2] border border-stone-200 rounded-lg book-shadow flex flex-col items-center justify-between p-12 text-center relative group">
            <div className="absolute left-0 top-0 bottom-0 w-6 border-r border-stone-100 bg-stone-50/30 rounded-l-lg" />
            <div className="pt-12 space-y-4">
              <h1 className="serif text-5xl font-light text-stone-900 leading-tight">生命的回响</h1>
            </div>
            <div className="pb-12 space-y-6">
              <p className="text-stone-400 font-light italic text-sm">你的故事，值得被记录。<br/>请慢慢说。</p>
              <div className="text-[10px] uppercase font-bold tracking-[0.4em] text-stone-300 group-hover:text-stone-900">{t.open}</div>
            </div>
          </div>
        </div>
      )}

      {step === 'intro' && (
        <div className="flex flex-col items-center justify-center space-y-12 py-10 animate-fade-in">
          <div className="max-w-2xl text-center space-y-4">
            <h2 className="serif text-6xl font-extralight text-stone-900">我在倾听。</h2>
            <p className="text-xl text-stone-400 font-light italic">我是你的叙事伙伴。我会替你记住所有你分享的细节。</p>
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 w-full max-w-2xl">
            <button onClick={initializeNewSession} className="p-10 bg-stone-900 text-stone-50 rounded-[2rem] shadow-xl hover:-translate-y-1 transition-all">{t.record}</button>
            <button onClick={() => setStep('timeline')} className="p-10 border border-stone-200 bg-white text-stone-700 rounded-[2rem] hover:-translate-y-1 transition-all">{t.archive}</button>
          </div>
        </div>
      )}

      {step === 'theme' && (
        <div className="space-y-10 animate-fade-in">
          <div className="text-center">
            <h2 className="serif text-4xl font-light">今天想聊聊什么？</h2>
          </div>
          <div className="flex flex-wrap justify-center gap-3 max-w-3xl mx-auto">
            {defaultThemes.map(th => (
              <button key={th} onClick={() => { setCurrentTheme(th); setStep('listen'); }} className="px-6 py-2 rounded-full border border-stone-200 text-sm hover:border-stone-900 transition-colors">{th}</button>
            ))}
            <div className="flex items-center space-x-2 w-full max-w-md mt-4">
              <input type="text" value={newThemeInput} onChange={(e) => setNewThemeInput(e.target.value)} placeholder="+ 自定义一个生命主题..." className="flex-grow bg-transparent border-b border-stone-200 py-2 outline-none serif italic" />
              <button onClick={() => { if(newThemeInput) { setCurrentTheme(newThemeInput); setStep('listen'); } }} className="text-stone-900 font-bold uppercase text-[10px] tracking-widest">开始</button>
            </div>
          </div>
        </div>
      )}

      {step === 'listen' && <ListeningModule theme={currentTheme} onFinish={handleFinishListening} />}

      {step === 'reflect' && (
        <div className="max-w-2xl mx-auto py-12 text-center space-y-10">
          <h2 className="serif text-4xl font-light italic">"我听到了你的分享..."</h2>
          <div className="p-10 bg-white border border-stone-100 rounded-[3rem] shadow-sm serif text-3xl leading-relaxed">
