          <div className="flex justify-center space-x-6">
            <button onClick={() => setStep('listen')} className="px-10 py-4 bg-stone-900 text-white rounded-full">再说一点</button>
            <button onClick={() => finalizeSession(currentTranscript)} className="px-10 py-4 border border-stone-200 rounded-full">就这些了</button>
          </div>
        </div>
      )}

      {step === 'distill' && (
        <div className="max-w-3xl mx-auto py-10 space-y-12">
          {loading ? (
            <div className="flex flex-col items-center justify-center py-20 space-y-4">
              <div className="w-12 h-12 border-4 border-stone-100 border-t-stone-900 rounded-full animate-spin"></div>
              <div className="serif italic text-2xl text-stone-400">我正在精心编织这段回忆...</div>
