import React from 'react';
import { TimelineEvent, LifePhase } from '../types';

interface TimelineViewProps {
  events: TimelineEvent[];
  labels: {
    recordedAt: string;
    empty: string;
  };
}

const TimelineView: React.FC<TimelineViewProps> = ({ events, labels }) => {
  const sortedEvents = [...events].sort((a, b) => {
    const order = ['Childhood', 'Youth', 'Adulthood', 'Seniority'];

    const getOrder = (phase: string) => {
      const p = phase?.charAt(0).toUpperCase() + phase?.slice(1).toLowerCase();
      const index = order.indexOf(p);
      return index === -1 ? 99 : index;
    };

    const orderA = getOrder(a.phase as string);
    const orderB = getOrder(b.phase as string);

    if (orderA !== orderB) return orderA - orderB;
    return (a.recordedAt || 0) - (b.recordedAt || 0);
  });

  return (
    <div className="relative py-10 pl-8 space-y-12 animate-fade-in">
      <div className="absolute left-[3.5px] top-0 bottom-0 w-[1px] bg-stone-200" />

      {sortedEvents.map((event, idx) => (
        <div key={event.id || idx} className="relative group">
          <div className="absolute left-[-32.5px] top-1.5 w-4 h-4 rounded-full border-2 border-[#fdfcf8] bg-stone-300 group-hover:bg-stone-900 group-hover:scale-125 transition-all duration-300" />

          <div className="space-y-2">
            <div className="flex items-center justify-between">
              <span className="text-[9px] font-bold uppercase tracking-widest text-stone-400 group-hover:text-stone-900 transition-colors">
                {event.phase} {event.timeRange ? `• ${event.timeRange}` : ''}
              </span>
              <span className="text-[9px] text-stone-300 italic font-medium">
                {labels.recordedAt}: {new Date(event.recordedAt).toLocaleDateString()}
              </span>
            </div>
            <h3 className="serif text-2xl font-medium text-stone-900 leading-tight">{event.event}</h3>
            <p className="text-stone-500 font-light leading-relaxed max-w-2xl serif italic opacity-80 group-hover:opacity-100 transition-opacity">
              {event.description}
            </p>
          </div>
        </div>
      ))}

      {sortedEvents.length === 0 && (
        <div className="text-stone-300 italic font-light py-20 text-center w-full serif text-xl">
          {labels.empty}
        </div>
      )}
    </div>
  );
};

export default TimelineView;

import React, { useState, useEffect, useRef } from 'react';
import { Language } from '../types';

interface ListeningModuleProps {
  theme: string;
  onFinish: (transcript: string) => void;
  lang: Language;
}

const ListeningModule: React.FC<ListeningModuleProps> = ({ theme, onFinish, lang }) => {
  const [isListening, setIsListening] = useState(false);
  const [transcript, setTranscript] = useState('');
  const [volume, setVolume] = useState(0);
  const [inputMode, setInputMode] = useState<'voice' | 'text'>('voice');
  const recognitionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);

  const t = {
    en: {
      header: "I am listening",
      voiceMode: "Voice Mode",
      textMode: "Text Mode",
      placeholder: "I am ready to read your story... Type here at your own pace.",
      finished: "Finished Writing",
      encouragement: "“Take your time. I am recording your words exactly as you speak them.”"
    },
    zh: {
      header: "我在倾听",
      voiceMode: "语音模式",
      textMode: "文字模式",
      placeholder: "我正准备好阅读你的故事... 请按照你的节奏输入。",
      finished: "完成书写",
      encouragement: "“慢慢来。我正在一字不差地记录你的述说。”"
    },
    es: {
      header: "Estoy escuchando",
      voiceMode: "Modo voz",
      textMode: "Modo texto",
      placeholder: "Estoy listo para leer tu historia... Escribe aquí a tu propio ritmo.",
      finished: "Terminar de escribir",
      encouragement: "“Tómate tu tiempo. Estoy grabando tus palabras exactamente como las dices.”"
    }
  }[lang];

  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition && inputMode === 'voice') {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = true;
      recognitionRef.current.interimResults = true;
      recognitionRef.current.lang = lang === 'zh' ? 'zh-CN' : lang === 'es' ? 'es-ES' : 'en-US';

      recognitionRef.current.onresult = (event: any) => {
        let interim = '';
        let final = '';
        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) final += event.results[i][0].transcript;
          else interim += event.results[i][0].transcript;
        }
        if (final) setTranscript(prev => prev + ' ' + final);
      };
      recognitionRef.current.onerror = () => setIsListening(false);
    }
    return () => { if (recognitionRef.current) recognitionRef.current.stop(); };
  }, [inputMode, lang]);

  const startListening = async () => {
    setIsListening(true);
    setTranscript('');
    if (recognitionRef.current) recognitionRef.current.start();
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      const source = audioContextRef.current.createMediaStreamSource(stream);
      analyserRef.current = audioContextRef.current.createAnalyser();
      source.connect(analyserRef.current);
      const dataArray = new Uint8Array(analyserRef.current.frequencyBinCount);
      const updateVolume = () => {
        if (!analyserRef.current) return;
        analyserRef.current.getByteFrequencyData(dataArray);
        setVolume(dataArray.reduce((a, b) => a + b) / dataArray.length);
        if (isListening) requestAnimationFrame(updateVolume);
      };
      updateVolume();
    } catch (err) { console.error(err); }
  };

  const stopListening = () => {
    setIsListening(false);
    if (recognitionRef.current) recognitionRef.current.stop();
    if (audioContextRef.current) audioContextRef.current.close();
    setTimeout(() => onFinish(transcript), 800);
  };

  return (
    <div className="flex flex-col items-center justify-center space-y-8 py-6 animate-fade-in w-full max-w-2xl mx-auto">
      <div className="text-center space-y-2">
        <h2 className="serif text-3xl font-light italic text-stone-800 tracking-tight">{t.header}: {theme}</h2>
        <div className="flex justify-center space-x-4">
          <button onClick={() => setInputMode('voice')} className={`text-[10px] uppercase tracking-[0.2em] font-bold ${inputMode === 'voice' ? 'text-stone-900 border-b border-stone-900' : 'text-stone-300'}`}>{t.voiceMode}</button>
          <button onClick={() => setInputMode('text')} className={`text-[10px] uppercase tracking-[0.2em] font-bold ${inputMode === 'text' ? 'text-stone-900 border-b border-stone-900' : 'text-stone-300'}`}>{t.textMode}</button>
        </div>
      </div>

      {inputMode === 'voice' ? (
        <div className="relative flex items-center justify-center h-64 w-64">
          <div className="absolute inset-0 bg-stone-200 rounded-full transition-all duration-300 ease-out" style={{ transform: `scale(${isListening ? 1 + (volume / 100) * 1.5 : 0.8})`, opacity: isListening ? 0.15 : 0.05 }} />
          <button
            onClick={isListening ? stopListening : startListening}
            className={`relative z-10 w-32 h-32 rounded-full flex flex-col items-center justify-center transition-all duration-700 shadow-xl ${isListening ? 'bg-stone-900' : 'bg-white border border-stone-100'}`}
          >
            {isListening ? <div className="w-8 h-8 bg-white rounded-sm" /> : <div className="w-0 h-0 border-t-[10px] border-t-transparent border-l-[18px] border-l-stone-400 border-b-[10px] border-b-transparent ml-1" />}
          </button>
        </div>
      ) : (
        <textarea 
          value={transcript} 
          onChange={(e) => setTranscript(e.target.value)}
          placeholder={t.placeholder}
          className="w-full h-64 p-8 serif text-2xl font-light italic bg-white border border-stone-100 rounded-[2rem] shadow-sm outline-none focus:border-stone-300 transition-colors resize-none"
        />
      )}

      {inputMode === 'text' && (
        <button onClick={() => onFinish(transcript)} disabled={!transcript.trim()} className="px-12 py-3 bg-stone-900 text-white rounded-full font-medium shadow-lg disabled:opacity-20 transition-all">{t.finished}</button>
      )}

      <div className="text-center italic text-stone-400 text-sm serif px-4 h-12">
        {isListening ? t.encouragement : ""}
      </div>
    </div>
  );
};

export default ListeningModule;

export enum LifePhase {
  CHILDHOOD = 'Childhood',
  YOUTH = 'Youth',
  ADULTHOOD = 'Adulthood',
  SENIORITY = 'Seniority'
}

export enum Visibility {
  PRIVATE = 'Private',
  FAMILY = 'Family Shared',
  LEGACY = 'Legacy'
}

export interface TimelineEvent {
  id: string;
  event: string;
  timeRange: string;
  phase: LifePhase;
  recordedAt: number;
  evidenceSessions: string[];
  description: string;
  confidence: number;
  visibility: Visibility;
}

export interface LifeWisdom {
  id: string;
  belief: string;
  explanation: string;
  recordedAt: number;
  evidenceSessions: string[];
  confidence: number;
  visibility: Visibility;
}

export interface MemorySession {
  id: string;
  timestamp: number;
  theme: string;
  transcript: string;
  polishedTranscript?: string;
  audioData?: string; // Base64 simulated storage
  detectedLanguages?: string[];
  status: 'active' | 'completed';
}

export interface PersonProfile {
  id: string;
  displayName: string;
  password?: string;
  sessions: MemorySession[];
  timeline: TimelineEvent[];
  wisdoms: LifeWisdom[];
}

export interface LifeMemoryStore {
  activePersonId: string | null;
  people: { [id: string]: PersonProfile };
}

export type Step = 'cover' | 'intro' | 'identity_select' | 'identity_init' | 'identity_setup_password' | 'identity_password' | 'theme' | 'listen' | 'reflect' | 'distill' | 'timeline' | 'legacy' | 'search';

