      let events = extraction?.events || [];

      setConflicts(extraction?.conflicts || []);

      if (events.length === 0) {
        events = [{
          event: currentTheme,
          phase: LifePhase.SENIORITY,
          description: transcript.slice(0, 150) + "...",
          confidence: 1,
          timeRange: currentT.fallbackTime
